const OrbitRing: React.FC<{ 
  value: number; 
  target: number; 
  color: string; 
  label: string; 
  icon: React.ReactNode 
}> = ({ value, target, color, label, icon }) => {
  const percentage = Math.min(100, (value / target) * 100);
