          >
             <div className="flex items-center">
                {/* Timer Info Side */}
                <div className="flex-1 pl-3 py-2">
                    <div className="flex items-center gap-1.5 mb-0.5">
                       <Database className="w-3.5 h-3.5 text-coquette-gold" />
