        set({
          vocabCount: state.vocabCount + vocab,
          immersionMinutes: state.immersionMinutes + immersion,
          grammarPoints: state.grammarPoints + grammar,
          streak: newStreak,
          lastLogDate: now.toISOString(),
          logs: [newLog, ...state.logs]
        });
      },

      addActivityLog: (entry) => set(state => ({
        activityLogs: [{ ...entry, id: crypto.randomUUID() }, ...state.activityLogs]
      })),

      toggleChapter: (id) => {
        const state = get();
        const exists = state.masteredChapters.includes(id);
        set({
          masteredChapters: exists
            ? state.masteredChapters.filter(c => c !== id)
            : [...state.masteredChapters, id]
        });
      },

      setModuleChapters: (ids, isSelected) => {
        const state = get();
        const current = new Set(state.masteredChapters);
        if (isSelected) ids.forEach(id => current.add(id));
        else ids.forEach(id => current.delete(id));
        set({ masteredChapters: Array.from(current) });
      },

      setGrammarContext: (text) => set({ grammarContext: text }),

      importGrammar: (text) => {
        const parsedData = parseAnkiExport(text);
        let totalImported = 0;
        const currentDb = get().grammarDatabase;
        const newDb = { ...currentDb };
        Object.entries(parsedData).forEach(([chapterId, points]) => {
            newDb[chapterId] = points;
            totalImported += points.length;
        });
        set({ grammarDatabase: newDb, grammarContext: text });
        return totalImported;
      },

      toggleDailyTask: (dateStr, taskId, type, value) => {
        const state = get();
        const fullKey = `${dateStr}-${taskId}`;
        const isCurrentlyDone = !!state.dailyChecklist[fullKey];
        const modifier = isCurrentlyDone ? -1 : 1;
        const valueChange = value * modifier;
        set({
          dailyChecklist: { ...state.dailyChecklist, [fullKey]: !isCurrentlyDone },
          vocabCount: type === 'vocab' ? Math.max(0, state.vocabCount + valueChange) : state.vocabCount,
          grammarPoints: type === 'grammar' ? Math.max(0, state.grammarPoints + valueChange) : state.grammarPoints,
          immersionMinutes: type === 'immersion' ? Math.max(0, state.immersionMinutes + valueChange) : state.immersionMinutes,
        });
      },

      toggleDate: (dateStr: string) => {
        const state = get();
        const currentDates = state.completedDates || {};
        const isMarkingComplete = !currentDates[dateStr];
        const newCompletedDates = { ...currentDates };

        if (!isMarkingComplete) {
          delete newCompletedDates[dateStr];
        } else {
          newCompletedDates[dateStr] = true;
        }

        set({
          completedDates: newCompletedDates,
          // Add 20 when marking complete, subtract 20 when unmarking
          vocabCount: Math.max(0, state.vocabCount + (isMarkingComplete ? 20 : -20))
        });
      },

      addKeepsake: (item) => set(state => ({ keepsakes: [item, ...state.keepsakes] })),
      updateKeepsake: (id, updates) => set(state => ({
        keepsakes: state.keepsakes.map(item => item.id === id ? { ...item, ...updates } : item)
      })),
      removeKeepsake: (id) => set(state => ({ keepsakes: state.keepsakes.filter(item => item.id !== id) })),

      addMinutesToKeepsake: (id, minutes) => set(state => ({
        keepsakes: state.keepsakes.map(item => 
          item.id === id ? { ...item, durationOrVolumes: (item.durationOrVolumes || 0) + minutes } : item
        )
      })),

      resetProgress: () => set({ 
        vocabCount: 2500, 
        immersionMinutes: 0, 
        grammarPoints: 0, 
        streak: 0, 
        lastLogDate: null, 
        logs: [],
        masteredChapters: [],
        grammarContext: '',
        grammarDatabase: {},
        dailyChecklist: {},
        completedDates: {},
        keepsakes: [],
        activityLogs: []
      }),

      resetToSeed: () => {
        // Updated to handle the nested structure of your actual backup data
        const stateData = (seedData as any).data?.['nihongo-nexus-storage']?.state;
        if (stateData) {
          set(stateData);
          // Ensure changes persist immediately
          const fullState = { state: get(), version: (seedData as any).version || 7 };
          localStorage.setItem(STORAGE_KEY, JSON.stringify(fullState));
        } else {
          console.error("Seed data state not found. Please check data/seedData.ts structure.");
        }
      }
    }),
    {
      name: STORAGE_KEY,
      version: 7,
      storage: createJSONStorage(() => localStorage),
      onRehydrateStorage: (state) => {
        const hasStorage = !!localStorage.getItem(STORAGE_KEY);
        if (!hasStorage) {
          return (hydratedState) => {
            if (hydratedState) {
              hydratedState.resetToSeed();
            }
          };
        }
      }
    }
  )
);

import { create } from 'zustand';
import { persist, createJSONStorage } from 'zustand/middleware';
import { isYesterday, isToday } from 'date-fns';
import { parseAnkiExport, ParsedGrammarPoint } from '../utils/grammarParser';
import { ActivityLogEntry, ActivityCategory } from '../types';
import { seedData } from '../data/seedData';

interface LogEntry {
  id: string;
  date: string;
  vocab: number;
  immersion: number;
  grammar: number;
}

export type MediaType = 'ANIME' | 'MANGA' | 'GAME' | 'SHOW';
export type MediaStatus = 'ONGOING' | 'FINISHED';

export interface Keepsake {
  id: string;
  title: string;
  type: MediaType;
  status: MediaStatus;
  coverUrl: string;
  rating: number;
  caption: string;
  durationOrVolumes: number;
  dateAdded: string;
  dateCompleted: string;
}

interface ProgressState {
  vocabCount: number;
  immersionMinutes: number;
  grammarPoints: number;
  streak: number;
  lastLogDate: string | null;
  logs: LogEntry[];
  masteredChapters: string[];
  grammarContext: string;
  grammarDatabase: Record<string, ParsedGrammarPoint[]>;
  dailyChecklist: Record<string, boolean>;
  completedDates: Record<string, boolean>;
  keepsakes: Keepsake[];
  activityLogs: ActivityLogEntry[];

  addLog: (vocab: number, immersion: number, grammar: number) => void;
  resetProgress: () => void;
  resetToSeed: () => void;
  toggleChapter: (id: string) => void;
  setModuleChapters: (ids: string[], isSelected: boolean) => void;
  setGrammarContext: (text: string) => void;
  importGrammar: (text: string) => number;
  toggleDailyTask: (dateStr: string, taskId: string, type: 'vocab' | 'grammar' | 'immersion', value: number) => void;
  toggleDate: (dateStr: string) => void;
  addKeepsake: (item: Keepsake) => void;
  updateKeepsake: (id: string, updates: Partial<Keepsake>) => void;
  removeKeepsake: (id: string) => void;
  addMinutesToKeepsake: (id: string, minutes: number) => void;
  addActivityLog: (entry: Omit<ActivityLogEntry, 'id'>) => void;
}

const STORAGE_KEY = 'nihongo-nexus-storage';

export const useProgressStore = create<ProgressState>()(
  persist(
    (set, get) => ({
      vocabCount: 2500,
      immersionMinutes: 0,
      grammarPoints: 0,
      streak: 0,
      lastLogDate: null,
      logs: [],
      masteredChapters: [],
      grammarContext: '',
      grammarDatabase: {},
      dailyChecklist: {},
      completedDates: {},
      keepsakes: [],
      activityLogs: [],

      addLog: (vocab, immersion, grammar) => {
        const state = get();
        const now = new Date();
        let newStreak = state.streak;
        if (state.lastLogDate) {
          const lastDate = new Date(state.lastLogDate);
          if (isYesterday(lastDate)) newStreak += 1;
          else if (!isToday(lastDate)) newStreak = 1;
        } else {
          newStreak = 1;
        }
        const newLog: LogEntry = {
          id: crypto.randomUUID(),
          date: now.toISOString(),
          vocab, immersion, grammar
        };
        set({
          vocabCount: state.vocabCount + vocab,
          immersionMinutes: state.immersionMinutes + immersion,
          grammarPoints: state.grammarPoints + grammar,
          streak: newStreak,
          lastLogDate: now.toISOString(),
          logs: [newLog, ...state.logs]
        });
      },

      addActivityLog: (entry) => set(state => ({
        activityLogs: [{ ...entry, id: crypto.randomUUID() }, ...state.activityLogs]
      })),

      toggleChapter: (id) => {
        const state = get();
        const exists = state.masteredChapters.includes(id);
        set({
          masteredChapters: exists
            ? state.masteredChapters.filter(c => c !== id)
            : [...state.masteredChapters, id]
        });
      },

      setModuleChapters: (ids, isSelected) => {
        const state = get();
        const current = new Set(state.masteredChapters);
        if (isSelected) ids.forEach(id => current.add(id));
        else ids.forEach(id => current.delete(id));
        set({ masteredChapters: Array.from(current) });
      },

      setGrammarContext: (text) => set({ grammarContext: text }),

      importGrammar: (text) => {
        const parsedData = parseAnkiExport(text);
        let totalImported = 0;
        const currentDb = get().grammarDatabase;
        const newDb = { ...currentDb };
        Object.entries(parsedData).forEach(([chapterId, points]) => {
          newDb[chapterId] = points;
          totalImported += points.length;
        });
        set({ grammarDatabase: newDb, grammarContext: text });
        return totalImported;
      },

      toggleDailyTask: (dateStr, taskId, type, value) => {
        const state = get();
        const fullKey = `${dateStr}-${taskId}`;
        const isCurrentlyDone = !!state.dailyChecklist[fullKey];
        const modifier = isCurrentlyDone ? -1 : 1;
        const valueChange = value * modifier;
        set({
          dailyChecklist: { ...state.dailyChecklist, [fullKey]: !isCurrentlyDone },
          vocabCount: type === 'vocab' ? Math.max(0, state.vocabCount + valueChange) : state.vocabCount,
          grammarPoints: type === 'grammar' ? Math.max(0, state.grammarPoints + valueChange) : state.grammarPoints,
          immersionMinutes: type === 'immersion' ? Math.max(0, state.immersionMinutes + valueChange) : state.immersionMinutes,
        });
      },

      toggleDate: (dateStr: string) => {
        const state = get();
        const currentDates = { ...(state.completedDates || {}) };
        const isMarkingComplete = !currentDates[dateStr];

        if (isMarkingComplete) {
          currentDates[dateStr] = true;
        } else {
          delete currentDates[dateStr];
        }

        set({
          completedDates: currentDates,
          vocabCount: Math.max(0, state.vocabCount + (isMarkingComplete ? 20 : -20))
        });
      },

      addKeepsake: (item) => set(state => ({ keepsakes: [item, ...state.keepsakes] })),
      updateKeepsake: (id, updates) => set(state => ({
        keepsakes: state.keepsakes.map(item => item.id === id ? { ...item, ...updates } : item)
      })),
      removeKeepsake: (id) => set(state => ({ keepsakes: state.keepsakes.filter(item => item.id !== id) })),
      addMinutesToKeepsake: (id, minutes) => set(state => ({
        keepsakes: state.keepsakes.map(item =>
          item.id === id ? { ...item, durationOrVolumes: (item.durationOrVolumes || 0) + minutes } : item
        )
      })),

      resetProgress: () => set({
        vocabCount: 2500, immersionMinutes: 0, grammarPoints: 0, streak: 0,
        lastLogDate: null, logs: [], masteredChapters: [], grammarContext: '',
        grammarDatabase: {}, dailyChecklist: {}, completedDates: {},
        keepsakes: [], activityLogs: []
      }),

      resetToSeed: () => {
        const incomingData = (seedData as any).data;
        if (!incomingData) return;

        // Restore main store
        const stateData = incomingData[STORAGE_KEY]?.state;
        if (stateData) {
          set(stateData);
          const fullState = { state: get(), version: (seedData as any).version || 7 };
          localStorage.setItem(STORAGE_KEY, JSON.stringify(fullState));
        }

        // Restore all secondary keys (history, timers, etc)
        Object.keys(incomingData).forEach(key => {
          if (key !== STORAGE_KEY) {
            const val = incomingData[key];
            const stringVal = typeof val === 'object' ? JSON.stringify(val) : String(val);
            localStorage.setItem(key, stringVal);
          }
        });
      }
    }),
    {
      name: STORAGE_KEY,
      version: 7,
      storage: createJSONStorage(() => localStorage),
      onRehydrateStorage: (state) => {
        const hasStorage = !!localStorage.getItem(STORAGE_KEY);
        if (!hasStorage) {
          return (hydratedState) => {
            if (hydratedState) hydratedState.resetToSeed();
          };
        }
      }
    }
  )
);

import { useState, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, Download, Upload, Database, Check, AlertCircle, FileJson, RefreshCw, Save, ShieldCheck, Sparkles, History } from 'lucide-react';
import { useProgressStore } from '../store/progressStore';

interface DataManagementModalProps {
  isOpen: boolean;
  onClose: () => void;
}

const TARGET_KEYS = [
  'nihongo-nexus-storage', 
  'messenger_contacts',    
  'messenger_history',     
  'messenger_total_time',  
  'grammar_total_time',    
  'anki_total_time',       
  'immersion_total_time',  
  'mission_scenarios'      
];

const DataManagementModal: React.FC<DataManagementModalProps> = ({ isOpen, onClose }) => {
  const [status, setStatus] = useState<'idle' | 'success' | 'error'>('idle');
  const [statusMsg, setStatusMsg] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  const resetToSeed = useProgressStore(state => state.resetToSeed);

  const handleExport = () => {
    try {
      const backupData: Record<string, any> = {};

      // First, capture all secondary keys
      TARGET_KEYS.forEach(key => {
        const raw = localStorage.getItem(key);
        if (raw) {
          try {
            backupData[key] = JSON.parse(raw);
          } catch {
            backupData[key] = raw;
          }
        }
      });

      // SYNC LOGIC: Ensure the main state numbers match the UI's accumulated timer time
      if (backupData['nihongo-nexus-storage']?.state) {
        const state = backupData['nihongo-nexus-storage'].state;

        // Update Immersion Minutes (accumulated seconds to minutes)
        const immersionSecs = Number(localStorage.getItem('immersion_total_time') || 0);
        state.immersionMinutes = Math.floor(immersionSecs / 60);

        // Optional: you can sync other derived stats here if needed
      }

      const payload = {
        meta: {
          app: 'nihongo-nexus',
          version: 2,
          timestamp: new Date().toISOString(),
          deviceName: navigator.userAgent.split(') ')[0].split(' (')[1] || 'Unknown Device'
        },
        data: backupData
      };

      const blob = new Blob([JSON.stringify(payload, null, 2)], { type: 'application/json' });
      const url = URL.createObjectURL(blob);

      const link = document.createElement('a');
      link.href = url;
      link.download = `nihongo-nexus-sync-${new Date().toISOString().split('T')[0]}.json`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);

      setStatus('success');
      setStatusMsg('Chronicle safely archived to disk.');
      setTimeout(() => setStatus('idle'), 3000);
    } catch (e) {
      console.error(e);
      setStatus('error');
      setStatusMsg('The archive failed to compile.');
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const json = JSON.parse(event.target?.result as string);
        if (!json.meta || json.meta.app !== 'nihongo-nexus' || !json.data) {
          throw new Error("Invalid format.");
        }
        performSmartMerge(json.data);
      } catch (e) {
        console.error(e);
        setStatus('error');
        setStatusMsg('Corrupt or incompatible backup file.');
      }
    };
    reader.readAsText(file);
  };

  const performSmartMerge = (incomingData: Record<string, any>) => {
    let mergeCount = 0;

    ['messenger_total_time', 'grammar_total_time', 'anki_total_time', 'immersion_total_time'].forEach(key => {
        if (incomingData[key]) {
            localStorage.setItem(key, String(incomingData[key]));
            mergeCount++;
        }
    });

    if (incomingData['messenger_contacts']) {
        localStorage.setItem('messenger_contacts', JSON.stringify(incomingData['messenger_contacts']));
        mergeCount++;
    }

    if (incomingData['messenger_history']) {
        localStorage.setItem('messenger_history', JSON.stringify(incomingData['messenger_history']));
        mergeCount++;
    }

    if (incomingData['nihongo-nexus-storage']) {
        localStorage.setItem('nihongo-nexus-storage', JSON.stringify(incomingData['nihongo-nexus-storage']));
        mergeCount++;
    }

    setStatus('success');
    setStatusMsg(`Sync Successful. Integrated ${mergeCount} modules.`);
    setTimeout(() => { window.location.reload(); }, 1500);
  };

  const handleResetToSeed = () => {
    if (confirm("This will replace your current progress with Pauline's original mastery stats. Continue?")) {
      resetToSeed();
      setStatus('success');
      setStatusMsg('Restored Pauline\'s Chronicle.');
      setTimeout(() => { window.location.reload(); }, 1000);
    }
  };

  if (!isOpen) return null;

  return (
    <AnimatePresence>
      <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
        <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="absolute inset-0 bg-black/60 backdrop-blur-md" onClick={onClose} />
        <motion.div initial={{ scale: 0.9, opacity: 0, y: 30 }} animate={{ scale: 1, opacity: 1, y: 0 }} exit={{ scale: 0.9, opacity: 0, y: 30 }} className="relative w-full max-w-lg bg-[#fffcfc] rounded-[40px] shadow-2xl overflow-hidden border border-coquette-border flex flex-col max-h-[90vh]">

          <div className="p-7 border-b border-rose-100 bg-rose-50/30 flex items-center justify-between">
            <div className="flex items-center gap-3">
               <div className="p-2.5 bg-white rounded-2xl border border-rose-100 text-rose-500 shadow-sm"><Database className="w-5 h-5" /></div>
               <div>
                 <h2 className="text-xl font-bold font-coquette-header text-gray-800">The Data Vault</h2>
                 <p className="text-[10px] text-rose-400 font-bold uppercase tracking-[0.2em] mt-0.5">Persistence Control</p>
               </div>
            </div>
            <button onClick={onClose} className="p-2 rounded-full hover:bg-white text-gray-300 hover:text-rose-400 transition-all"><X className="w-5 h-5" /></button>
          </div>

          <div className="p-8 space-y-6 overflow-y-auto custom-scrollbar flex-1">
             {status !== 'idle' && (
               <motion.div initial={{ opacity: 0, y: -10 }} animate={{ opacity: 1, y: 0 }} className={`p-4 rounded-2xl flex items-center gap-3 text-sm font-bold shadow-sm border ${status === 'success' ? 'bg-emerald-50 text-emerald-600 border-emerald-100' : 'bg-red-50 text-red-500 border-red-100'}`}>
                 {status === 'success' ? <ShieldCheck className="w-5 h-5" /> : <AlertCircle className="w-5 h-5" />}
                 {statusMsg}
                 {status === 'success' && <RefreshCw className="w-4 h-4 animate-spin ml-auto" />}
               </motion.div>
             )}

             <div className="grid grid-cols-2 gap-4">
                <button onClick={handleExport} className="group flex flex-col items-center justify-center p-6 rounded-[24px] border border-rose-100 bg-white hover:border-rose-300 hover:shadow-lg transition-all gap-2">
                  <div className="w-12 h-12 rounded-full bg-rose-50 flex items-center justify-center text-rose-400 group-hover:bg-rose-400 group-hover:text-white transition-all"><Download className="w-6 h-6" /></div>
                  <div className="text-center">
                    <h3 className="font-bold text-gray-700 text-xs font-coquette-header">Backup</h3>
                    <p className="text-[8px] text-gray-400 uppercase tracking-widest">To .JSON</p>
                  </div>
                </button>

                <button onClick={() => fileInputRef.current?.click()} className="group flex flex-col items-center justify-center p-6 rounded-[24px] border border-dashed border-gray-200 bg-gray-50/30 hover:border-rose-400 hover:bg-rose-50 transition-all gap-2">
                  <div className="w-12 h-12 rounded-full bg-white flex items-center justify-center text-gray-400 group-hover:text-rose-500 transition-all"><Upload className="w-6 h-6" /></div>
                  <div className="text-center">
                    <h3 className="font-bold text-gray-700 text-xs font-coquette-header">Restore</h3>
                    <p className="text-[8px] text-gray-400 uppercase tracking-widest">Merge Sync</p>
                  </div>
                  <input type="file" ref={fileInputRef} onChange={handleFileUpload} accept=".json" className="hidden" />
                </button>
             </div>

             <button 
                onClick={handleResetToSeed}
                className="w-full group p-6 rounded-[32px] border-2 border-rose-100 bg-pink-50/20 hover:bg-rose-50 hover:border-rose-300 transition-all flex flex-col items-center gap-3 relative overflow-hidden"
             >
                <div className="absolute top-[-20%] left-[-10%] w-32 h-32 bg-white/40 blur-3xl rounded-full"></div>
                <div className="w-16 h-16 rounded-full bg-white shadow-md flex items-center justify-center text-rose-400 group-hover:scale-110 transition-transform relative z-10">
                   <History className="w-8 h-8" />
                   <Sparkles className="absolute -top-1 -right-1 w-5 h-5 text-coquette-gold animate-pulse" />
                </div>
                <div className="text-center relative z-10">
                   <h3 className="font-bold text-rose-900 font-coquette-header text-lg">Restore Pauline's Archive</h3>
                   <p className="text-[10px] text-coquette-subtext mt-1 uppercase font-bold tracking-[0.2em]">Reset to Master Seeds</p>
                </div>
             </button>
          </div>
          <div className="p-5 bg-gray-50/50 border-t border-rose-50 text-center">
             <span className="text-[9px] text-gray-400 font-black uppercase tracking-[0.3em]">Nihongo Nexus Protocol v2.2 (Sync Fix)</span>
          </div>
        </motion.div>
      </div>
    </AnimatePresence>
  );
};

