import React, { useRef, useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { MOCK_IMMERSION_VIDEOS } from '../../data/immersionData';
import ImmersionStage from './ImmersionStage';
import { Clapperboard, ChevronDown, BookHeart } from 'lucide-react';

const ImmersionFeed: React.FC = () => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [activeIndex, setActiveIndex] = useState(0);

  const handleScroll = () => {
    if (!containerRef.current) return;
    const scrollPos = containerRef.current.scrollTop;
    const height = containerRef.current.clientHeight;
    const newIndex = Math.round(scrollPos / height);
    if (newIndex !== activeIndex) {
      setActiveIndex(newIndex);
    }
  };

  return (
    <div className="h-screen w-full relative overflow-hidden bg-rose-50/50">
      {/* Floating Header UI */}
      <div className="absolute top-0 left-0 right-0 z-50 pointer-events-none p-6 flex items-center justify-between">
         <div className="flex items-center gap-3">
            <div className="w-12 h-12 rounded-full bg-white shadow-xl flex items-center justify-center text-coquette-accent border border-rose-100">
               <Clapperboard className="w-6 h-6" />
            </div>
            <div className="flex flex-col">
              <h1 className="text-2xl font-coquette-header text-coquette-text drop-shadow-sm">Immersion Theater</h1>
              <span className="text-[10px] font-black text-rose-400 uppercase tracking-[0.3em]">Cinematic Learning</span>
            </div>
         </div>

         <div className="flex items-center gap-4 pointer-events-auto">
            <div className="hidden md:flex flex-col items-end mr-2">
               <span className="text-[9px] font-black text-coquette-subtext uppercase tracking-widest">Active Scene</span>
               <span className="text-xs font-bold text-coquette-text">{activeIndex + 1} of {MOCK_IMMERSION_VIDEOS.length}</span>
            </div>
            <button className="p-3 rounded-full bg-white shadow-lg text-coquette-accent border border-rose-100 hover:scale-110 transition-transform">
               <BookHeart className="w-6 h-6" />
            </button>
         </div>
      </div>

      {/* Main Feed Container */}
      <div 
        ref={containerRef}
        onScroll={handleScroll}
        className="h-screen overflow-y-scroll snap-y snap-mandatory scroll-smooth scrollbar-hide"
      >
        {MOCK_IMMERSION_VIDEOS.map((video, idx) => (
          <ImmersionStage 
            key={video.id} 
            video={video} 
            isActive={activeIndex === idx} 
          />
        ))}
      </div>

      {/* Floating Action Hint */}
      <motion.div 
        animate={{ y: [0, 10, 0] }}
        transition={{ duration: 2, repeat: Infinity }}
        className="absolute bottom-10 left-1/2 -translate-x-1/2 z-50 pointer-events-none opacity-40"
      >
         <div className="flex flex-col items-center gap-2">
            <span className="text-[9px] font-black uppercase tracking-[0.4em] text-coquette-subtext">Swipe Down</span>
            <ChevronDown className="w-6 h-6 text-coquette-accent" />
         </div>
      </motion.div>
    </div>
  );
};

export default ImmersionFeed;

