import ImmersionStage from './ImmersionStage';
import { Clapperboard, ChevronDown, BookHeart, PanelLeftClose, PanelLeft } from 'lucide-react';

interface ImmersionFeedProps {
  isSidebarVisible: boolean;
  onToggleSidebar: () => void;
}

const ImmersionFeed: React.FC<ImmersionFeedProps> = ({ isSidebarVisible, onToggleSidebar }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [activeIndex, setActiveIndex] = useState(0);

  const handleScroll = () => {
    if (!containerRef.current) return;
    const scrollPos = containerRef.current.scrollTop;
    const height = containerRef.current.clientHeight;
    const newIndex = Math.round(scrollPos / height);
    if (newIndex !== activeIndex) {
      setActiveIndex(newIndex);
    }
  };

  return (
    <div className="h-screen w-full relative overflow-hidden bg-rose-50/50">
      {/* Floating Header UI */}
      <div className="absolute top-0 left-0 right-0 z-50 pointer-events-none p-6 flex items-center justify-between">
         <div className="flex items-center gap-3">
            <div className="w-12 h-12 rounded-full bg-white shadow-xl flex items-center justify-center text-coquette-accent border border-rose-100">
               <Clapperboard className="w-6 h-6" />
            </div>
            <div className="flex flex-col">
              <h1 className="text-2xl font-coquette-header text-coquette-text drop-shadow-sm">Immersion Theater</h1>
              <span className="text-[10px] font-black text-rose-400 uppercase tracking-[0.3em]">Cinematic Learning</span>
            </div>
         </div>

         <div className="flex items-center gap-4 pointer-events-auto">
            {/* Sidebar Toggle Slider */}
            <div className="hidden sm:flex items-center bg-white/40 backdrop-blur-md rounded-full border border-rose-100 p-1 mr-4 shadow-sm">
               <button 
                 onClick={onToggleSidebar}
                 className={`flex items-center gap-2 px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest transition-all
                   ${isSidebarVisible ? 'bg-white text-rose-400 shadow-sm' : 'text-rose-300 hover:text-rose-400'}
                 `}
               >
                 <PanelLeft className="w-3 h-3" /> Sidebar On
               </button>
               <button 
                 onClick={onToggleSidebar}
                 className={`flex items-center gap-2 px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest transition-all
                   ${!isSidebarVisible ? 'bg-white text-rose-400 shadow-sm' : 'text-rose-300 hover:text-rose-400'}
                 `}
               >
                 <PanelLeftClose className="w-3 h-3" /> Theater Mode
               </button>
            </div>

            <div className="hidden md:flex flex-col items-end mr-2">
               <span className="text-[9px] font-black text-coquette-subtext uppercase tracking-widest">Active Scene</span>
               <span className="text-xs font-bold text-coquette-text">{activeIndex + 1} of {MOCK_IMMERSION_VIDEOS.length}</span>
            </div>
            <button className="p-3 rounded-full bg-white shadow-lg text-coquette-accent border border-rose-100 hover:scale-110 transition-transform">
               <BookHeart className="w-6 h-6" />
            </button>
         </div>
      </div>

      {/* Main Feed Container */}
      <div 
        ref={containerRef}
        onScroll={handleScroll}
        className="h-screen overflow-y-scroll snap-y snap-mandatory scroll-smooth scrollbar-hide"
      >
        {MOCK_IMMERSION_VIDEOS.map((video, idx) => (
          <ImmersionStage 
            key={video.id} 
            video={video} 
            isActive={activeIndex === idx} 
          />
        ))}
      </div>

      {/* Floating Action Hint */}
      <motion.div 
        animate={{ y: [0, 10, 0] }}
        transition={{ duration: 2, repeat: Infinity }}
        className="absolute bottom-10 left-1/2 -translate-x-1/2 z-50 pointer-events-none opacity-40"
      >
         <div className="flex flex-col items-center gap-2">
            <span className="text-[9px] font-black uppercase tracking-[0.4em] text-coquette-subtext">Swipe Down</span>
            <ChevronDown className="w-6 h-6 text-coquette-accent" />
         </div>
      </motion.div>
    </div>
  );
};

export default ImmersionFeed;

import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { PanelLeft } from 'lucide-react';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import QuestMap from './components/QuestMap';
import SenseiChat from './components/SenseiChat';
import LogModal from './components/LogModal';
import SyntaxArchive from './components/SyntaxArchive';
import KeepsakesTab from './components/KeepsakesTab';
import MessengerTab from './components/MessengerTab';
import ActivityLogTab from './components/ActivityLogTab';
import ImmersionFeed from './components/immersion/ImmersionFeed';
import { View } from './types';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>('dashboard');
  const [isChatOpen, setIsChatOpen] = useState(false);
  const [isLogModalOpen, setIsLogModalOpen] = useState(false);
  const [isSidebarVisible, setIsSidebarVisible] = useState(true);

  const toggleSidebar = () => setIsSidebarVisible(!isSidebarVisible);

  return (
    <div className="min-h-screen font-sans selection:bg-coquette-accent selection:text-white overflow-hidden relative transition-colors duration-500 bg-coquette-bg text-coquette-text">
      {/* Background Layer */}
      <div className="fixed inset-0 z-0 bg-coquette-bg">
         <div className="absolute inset-0 opacity-40 bg-[url('https://www.transparenttextures.com/patterns/cream-paper.png')]"></div>
         <div className="absolute top-[-10%] left-[-10%] w-[500px] h-[500px] bg-pink-200/20 rounded-full blur-[100px]"></div>
         <div className="absolute bottom-[-10%] right-[-10%] w-[500px] h-[500px] bg-coquette-gold/10 rounded-full blur-[100px]"></div>
      </div>

      <div className="relative z-10 flex h-screen">
        <Sidebar 
          currentView={currentView} 
          onViewChange={setCurrentView}
          onSummonSensei={() => setIsChatOpen(true)}
          isHidden={!isSidebarVisible}
        />

        {/* Floating Sidebar Restore Tab */}
        <AnimatePresence>
          {!isSidebarVisible && (
            <motion.button
              initial={{ x: -50, opacity: 0 }}
              animate={{ x: 0, opacity: 1 }}
              exit={{ x: -50, opacity: 0 }}
              onClick={toggleSidebar}
              className="fixed left-0 top-1/2 -translate-y-1/2 z-[70] bg-white border-y border-r border-rose-100 p-3 rounded-r-2xl shadow-xl text-rose-300 hover:text-rose-500 hover:pl-5 transition-all group"
              title="Show Sidebar"
            >
              <PanelLeft className="w-5 h-5" />
            </motion.button>
          )}
        </AnimatePresence>

        <main 
          className={`
            flex-1 overflow-y-auto transition-all duration-500 scrollbar-thin scrollbar-thumb-coquette-accent
            ${isSidebarVisible ? 'pl-20 lg:pl-64' : 'pl-0'}
            ${currentView === 'theater' ? 'bg-black' : ''}
          `}
        >
          {currentView === 'dashboard' && <Dashboard onOpenLogModal={() => setIsLogModalOpen(true)} />}
          {currentView === 'questmap' && <QuestMap />}
          {currentView === 'theater' && (
            <ImmersionFeed 
              isSidebarVisible={isSidebarVisible} 
              onToggleSidebar={toggleSidebar} 
            />
          )}
          {currentView === 'syntax' && <SyntaxArchive />}
          {currentView === 'inventory' && <KeepsakesTab />}
          {currentView === 'messenger' && <MessengerTab />}
          {currentView === 'activity' && <ActivityLogTab />}
        </main>

        <SenseiChat isOpen={isChatOpen} onClose={() => setIsChatOpen(false)} />
      </div>

      <LogModal isOpen={isLogModalOpen} onClose={() => setIsLogModalOpen(false)} />
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  LayoutDashboard, 
  Map, 
  Sparkles, 
  Database, 
  Feather, 
  BookHeart, 
  Scroll, 
  MessageCircleHeart, 
  Activity,
  Volume2,
  VolumeX,
  Clapperboard,
  PanelLeftClose
} from 'lucide-react';
import { View } from '../types';
import { SIDEBAR_VIDEOS } from '../constants';

interface SidebarProps {
  currentView: View;
  onViewChange: (view: View) => void;
  onSummonSensei: () => void;
  isHidden?: boolean;
  onToggleHide?: () => void;
}

const SidebarVideoWidget: React.FC = () => {
  const [currentVideoIndex, setCurrentVideoIndex] = useState(0);
  const [isMuted, setIsMuted] = useState(true);

  const handleVideoEnd = () => {
    setCurrentVideoIndex((prev) => (prev + 1) % SIDEBAR_VIDEOS.length);
  };

  const toggleMute = (e: React.MouseEvent) => {
    e.stopPropagation();
    setIsMuted(!isMuted);
  };

  return (
    <div className="px-4 mb-4 hidden lg:block">
      <div 
        onClick={toggleMute}
        className="w-full aspect-square rounded-2xl overflow-hidden relative shadow-sm group cursor-pointer bg-gray-50"
      >
        <video
          key={SIDEBAR_VIDEOS[currentVideoIndex]}
          src={SIDEBAR_VIDEOS[currentVideoIndex]}
          autoPlay
          muted={isMuted}
          playsInline
          onEnded={handleVideoEnd}
          className="w-full h-full object-cover grayscale-[0.2] sepia-[0.1]"
        />

        <div className="absolute inset-0 bg-black/0 group-hover:bg-black/10 transition-colors pointer-events-none" />

        <div className="absolute bottom-2 right-2 p-1.5 bg-black/20 backdrop-blur-md rounded-full text-white opacity-0 group-hover:opacity-100 transition-opacity">
          {isMuted ? <VolumeX size={12} /> : <Volume2 size={12} />}
        </div>
      </div>
    </div>
  );
};

const Sidebar: React.FC<SidebarProps> = ({ currentView, onViewChange, onSummonSensei, isHidden = false, onToggleHide }) => {
  const navItems = [
    { id: 'dashboard', label: 'My Journal', icon: Feather },
    { id: 'questmap', label: 'Journey Map', icon: Map },
    { id: 'theater', label: 'Theater', icon: Clapperboard },
    { id: 'syntax', label: 'Grammar Notes', icon: Scroll },
    { id: 'activity', label: 'Activity Log', icon: Activity },
    { id: 'inventory', label: 'Keepsakes', icon: Sparkles },
    { id: 'messenger', label: 'Messenger', icon: MessageCircleHeart },
  ];

  return (
    <motion.aside 
      initial={false}
      animate={{ x: isHidden ? '-100%' : 0 }}
      transition={{ type: 'spring', stiffness: 300, damping: 30 }}
      className="w-20 lg:w-64 h-screen flex flex-col fixed left-0 top-0 z-[60] bg-[#fffcfc] border-r-4 border-double border-coquette-gold/30 shadow-xl"
    >
      <div className="p-6 flex items-center justify-center lg:justify-start space-x-3 border-b border-coquette-border">
         <Sparkles className="w-6 h-6 text-coquette-gold animate-pulse" />
        <span className="hidden lg:block font-bold text-xl tracking-widest font-coquette-header text-coquette-text">
          Study Diary
        </span>
      </div>

      <nav className="flex-1 py-8 flex flex-col gap-3 px-3">
        {navItems.map((item) => {
          const isActive = currentView === item.id;
          return (
            <div key={item.id} className="relative group">
              <button
                onClick={() => onViewChange(item.id as View)}
                className={`w-full flex items-center space-x-4 p-3 rounded-r-full transition-all duration-300 relative overflow-hidden font-coquette-body
                  ${isActive 
                    ? 'bg-coquette-accent/20 text-coquette-text border-l-4 border-coquette-accent' 
                    : 'text-coquette-subtext hover:bg-coquette-bg hover:text-coquette-text hover:pl-5'}
                `}
              >
                <item.icon className={`w-5 h-5 flex-shrink-0 ${isActive ? 'text-coquette-accent fill-coquette-accent/20' : 'group-hover:text-coquette-gold'}`} />
                <span className="hidden lg:block text-lg truncate flex-1 text-left">{item.label}</span>

                {/* Specific Hide Button for Theater */}
                {item.id === 'theater' && (
                  <motion.div 
                    initial={{ opacity: 0, x: 10 }}
                    whileHover={{ scale: 1.1 }}
                    animate={{ opacity: 1, x: 0 }}
                    onClick={(e) => {
                      e.stopPropagation();
                      onToggleHide?.();
                    }}
                    className="hidden lg:flex p-1.5 rounded-full bg-white border border-rose-100 text-rose-300 hover:text-rose-500 shadow-sm transition-colors mr-2"
                    title="Hide Sidebar"
                  >
                    <PanelLeftClose className="w-3.5 h-3.5" />
                  </motion.div>
                )}
              </button>
            </div>
          );
        })}
      </nav>

      <div className="p-4 flex flex-col">
        <SidebarVideoWidget />

        <button
          onClick={onSummonSensei}
          className="w-full flex items-center justify-center lg:justify-start space-x-3 p-4 rounded-lg transition-all duration-300 transform hover:scale-[1.02] bg-white border border-coquette-gold/50 text-coquette-text shadow-[0_4px_10px_rgba(212,163,115,0.2)] hover:shadow-[0_4px_15px_rgba(212,163,115,0.4)] font-coquette-body italic"
        >
          <BookHeart className="w-5 h-5 text-coquette-accent" />
          <span className="hidden lg:block">Consult Guide</span>
        </button>
      </div>
    </motion.aside>
  );
};

export default Sidebar;

