import { ImmersionToken, TokenType } from '../../types/immersionSchema';
import { ChevronRight } from 'lucide-react';

interface TranscriptStreamProps {
  dialogue: DialogueLine[];
}

const TokenChip: React.FC<{ 
  token: ImmersionToken; 
  isHovered: boolean; 
  onHover: (groupId: number | null) => void 
}> = ({ token, isHovered, onHover }) => {
  const isPunctuation = token.type === TokenType.PUNCTUATION;
  const isGrammar = token.type === TokenType.GRAMMAR;

  return (
    <span
      onMouseEnter={() => !isPunctuation && onHover(token.groupId)}
      onMouseLeave={() => onHover(null)}
      className={`
        inline-flex flex-col items-center transition-all duration-200 cursor-default px-0.5 rounded
        ${isHovered ? 'bg-rose-100 shadow-[0_0_8px_rgba(244,172,183,0.3)]' : ''}
        ${isPunctuation ? 'text-gray-300' : ''}
      `}
    >
      <span className={`
        text-base md:text-lg font-coquette-rounded 
        ${isGrammar ? 'italic opacity-60 font-medium' : 'font-bold text-coquette-text'}
        ${isHovered ? 'text-rose-600' : ''}
      `}>
        {token.text}
      </span>
    </span>
  );
};

const TranscriptLine: React.FC<{ line: DialogueLine }> = ({ line }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [hoveredGroupId, setHoveredGroupId] = useState<number | null>(null);

  return (
    <div className="mb-4">
      <motion.div
        layout
        className={`w-full text-left p-5 px-6 rounded-[28px] transition-all duration-300 border
          ${isOpen 
            ? 'bg-white border-rose-200 shadow-xl' 
            : 'bg-white/60 border-rose-50/50 hover:border-rose-200 hover:bg-white'}
        `}
      >
        <div className="flex items-start justify-between gap-6">
           <div className="flex-1">
              {/* Speaker Label */}
              <div className="flex items-center gap-2 mb-2">
                 <span className="text-[8px] font-black uppercase tracking-[0.2em] text-rose-300 bg-rose-50 px-2 py-0.5 rounded-full">
                    {line.speaker}
                 </span>
              </div>

              {/* Japanese Token Stream */}
              <div className="flex flex-wrap items-end gap-x-1.5 gap-y-1 mb-1">
                {line.japanese.map((t, i) => (
                  <TokenChip 
                    key={i} 
                    token={t} 
                    isHovered={hoveredGroupId !== null && hoveredGroupId !== 0 && t.groupId === hoveredGroupId}
                    onHover={setHoveredGroupId}
                  />
                ))}
              </div>

              {/* English Stream (Static Teaser or Full depending on state) */}
              <AnimatePresence mode="wait">
                {isOpen ? (
                  <motion.div
                    initial={{ height: 0, opacity: 0 }}
                    animate={{ height: 'auto', opacity: 1 }}
                    exit={{ height: 0, opacity: 0 }}
                    className="overflow-hidden"
                  >
                    <div className="pt-3 mt-3 border-t border-rose-100/30 flex flex-wrap items-center gap-x-1 gap-y-0.5">
                       {line.english.map((t, i) => (
                         <span 
                           key={i}
                           onMouseEnter={() => t.type !== TokenType.PUNCTUATION && setHoveredGroupId(t.groupId)}
                           onMouseLeave={() => setHoveredGroupId(null)}
                           className={`
                             text-xs md:text-sm font-coquette-rounded transition-colors px-0.5 rounded
                             ${t.type === TokenType.GRAMMAR ? 'italic opacity-50' : 'text-gray-500 font-medium'}
                             ${hoveredGroupId !== null && hoveredGroupId !== 0 && t.groupId === hoveredGroupId ? 'bg-rose-100 text-rose-600' : ''}
                           `}
                         >
                           {t.text}
                         </span>
                       ))}
                    </div>
                    {line.grammarNotes && line.grammarNotes.length > 0 && (
                      <div className="mt-4 bg-rose-50/50 p-3 rounded-xl border border-rose-100/50">
                        <p className="text-[9px] font-black uppercase text-rose-300 tracking-widest mb-1">Grammar Notes</p>
                        <ul className="space-y-1">
                           {line.grammarNotes.map((note, idx) => (
                             <li key={idx} className="text-[10px] text-gray-400 font-medium leading-relaxed italic">• {note}</li>
                           ))}
                        </ul>
                      </div>
                    )}
                  </motion.div>
                ) : (
                  <button 
                    onClick={() => setIsOpen(true)}
                    className="text-[10px] text-rose-300 font-bold uppercase tracking-widest hover:text-rose-400 transition-colors mt-2"
                  >
                    Reveal Translation
                  </button>
                )}
              </AnimatePresence>
           </div>

           <button 
              onClick={() => setIsOpen(!isOpen)}
              className={`flex-shrink-0 p-2 mt-2 rounded-full transition-all ${isOpen ? 'bg-rose-50 text-coquette-accent rotate-90' : 'text-rose-200'}`}
           >
              <ChevronRight className="w-4 h-4" />
           </button>
        </div>
      </motion.div>
    </div>
