import { GoogleGenAI, Type } from "@google/genai";
import { VideoAnalysis } from "../types/immersionSchema";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * The "Immersion Engine"
 * Analyzes audio/video data to produce conceptual color-coded transcripts.
 */
export const analyzeImmersionMedia = async (base64Data: string, mimeType: string): Promise<VideoAnalysis> => {
  const prompt = `
    Analyze the provided media. Return a strict JSON structure that synchronizes Japanese grammar with English concepts.

    CRITICAL PROCESSING RULES:
    1. Morpheme Splitting (Japanese): Split verbs/adjectives into Root (CONTENT) and Conjugation (GRAMMAR).
       Ex: "Tabetakatta" -> [Tabe (CONTENT)] + [ta (GRAMMAR)] + [katta (GRAMMAR)].
    2. Semantic Linking (groupId): Assign a unique integer ID to distinct concepts. 
       If JP "Ringo" maps to EN "Apple", they share the same groupId.
    3. Type Logic:
       CONTENT: Nouns, Verb Roots, Adjective Roots, Adverbs.
       GRAMMAR: Particles (wa, ga, ni, wo, etc), Copulas, Verb Endings, Connectors.
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: [
      {
        inlineData: {
          data: base64Data,
          mimeType: mimeType,
        },
      },
      {
        text: prompt,
      },
    ],
    config: {
      responseMimeType: 'application/json',
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          nodes: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                id: { type: Type.STRING },
                timestampStart: { type: Type.NUMBER },
                timestampEnd: { type: Type.NUMBER },
                speaker: { type: Type.STRING },
                japanese: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      text: { type: Type.STRING },
                      romaji: { type: Type.STRING },
                      type: { type: Type.STRING },
                      groupId: { type: Type.INTEGER }
                    },
                    required: ["text", "type", "groupId"]
                  }
                },
                english: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      text: { type: Type.STRING },
                      type: { type: Type.STRING },
                      groupId: { type: Type.INTEGER }
                    },
                    required: ["text", "type", "groupId"]
                  }
                }
              },
              required: ["id", "timestampStart", "timestampEnd", "speaker", "japanese", "english"]
            }
          }
        },
        required: ["nodes"]
      }
    }
  });

  if (response.text) {
    return JSON.parse(response.text) as VideoAnalysis;
  }
  throw new Error("Failed to analyze media");
};

