const TokenChip: React.FC<{ 
  token: ImmersionToken; 
  isHovered: boolean; 
  onHover: (groupId: number | null) => void;
  onClick: (token: ImmersionToken) => void;
  isEnglish?: boolean;
}> = ({ token, isHovered, onHover, onClick, isEnglish = false }) => {
  const isPunctuation = token.type === TokenType.PUNCTUATION;
  const isGrammar = token.type === TokenType.GRAMMAR;

  return (
    <span
      onMouseEnter={() => !isPunctuation && onHover(token.groupId)}
      onMouseLeave={() => onHover(null)}
      onClick={(e) => {
        if (!isPunctuation) {
          e.stopPropagation();
          onClick(token);
        }
      }}
      className={`
        inline-flex transition-all duration-150 cursor-pointer px-0.5 rounded
        ${isHovered ? 'bg-rose-100/80' : 'hover:bg-rose-50/50'}
        ${isPunctuation ? 'text-gray-300' : ''}
      `}
    >
      <span className={`
        font-coquette-rounded leading-tight
        ${isEnglish ? 'text-[11px] md:text-xs' : 'text-base md:text-lg'}
        ${isGrammar ? 'text-rose-400 font-medium' : (isEnglish ? 'text-gray-500 font-medium' : 'font-bold text-coquette-text')}
        ${isHovered ? 'text-rose-700' : ''}
      `}>
        {token.text}
      </span>
    </span>
  );
};

