const TranscriptStream: React.FC<TranscriptStreamProps> = ({ dialogue }) => {
  const [activeExplanation, setActiveExplanation] = useState<ExplanationCard | null>(null);
  const [isExplaining, setIsExplaining] = useState(false);

  const handleTokenClick = async (token: ImmersionToken, line: DialogueLine) => {
    const context = line.japanese.map(t => t.text).join('');
    setIsExplaining(true);
    setActiveExplanation(null);
    try {
      const data = await explainToken(context, token.text);
      setActiveExplanation(data);
    } catch (e) {
      console.error(e);
    } finally {
      setIsExplaining(false);
    }
  };

  return (
    <div className="h-full flex flex-col overflow-hidden relative">
      {/* Scrollable Container */}
      <div className="flex-1 overflow-y-auto p-4 lg:p-10 scrollbar-thin scrollbar-thumb-rose-100 bg-[url('https://www.transparenttextures.com/patterns/cream-paper.png')]">
        <div className="max-w-xl mx-auto">
          {dialogue.map((line) => (
            <TranscriptLine key={line.id} line={line} onTokenClick={handleTokenClick} />
          ))}
          {/* Bottom Spacing for long scrolls */}
          <div className="h-32" />
        </div>
      </div>

      <SenseiModal 
        explanation={activeExplanation} 
        isLoading={isExplaining} 
        onClose={() => setActiveExplanation(null)} 
      />
    </div>
  );
};

export default TranscriptStream;

import { create } from 'zustand';
import { persist, createJSONStorage } from 'zustand/middleware';
import { VideoAnalysis, DialogueNode } from '../types/immersionSchema';
import { format, addHours } from 'date-fns';
import { useProgressStore } from './progressStore';

interface SessionStats {
  totalSecondsWatched: number;
  nodesCompleted: number;
}

interface ImmersionState {
  // Persistent Data
  playlist: VideoAnalysis[];
  isTranslationVisible: boolean;
  autoScrollEnabled: boolean;

  // In-Memory Data (not persisted to avoid 5MB localStorage limit)
  activeIndex: number;
  videoSources: Record<string, string>; // Maps videoId to ObjectURL
  sessionStats: SessionStats;

  // Actions
  addVideo: (videoFile: File, analysis: VideoAnalysis) => void;
  nextScene: () => void;
  prevScene: () => void;
  setActiveIndex: (index: number) => void;
  toggleTranslation: () => void;
  recordWatchTime: (seconds: number, videoId: string) => void;
  markNodeComplete: (nodeId: string) => void;

  // Helpers
  getVirtualDate: () => string;
  getCurrentVideo: () => VideoAnalysis | null;
}

export const useImmersionStore = create<ImmersionState>()(
  persist(
    (set, get) => ({
      playlist: [],
      isTranslationVisible: false,
      autoScrollEnabled: true,
      activeIndex: 0,
      videoSources: {},
      sessionStats: {
        totalSecondsWatched: 0,
        nodesCompleted: 0,
      },

      getVirtualDate: () => {
        // 6:00 AM cutoff logic
        return format(addHours(new Date(), -6), 'yyyy-MM-dd');
      },

      getCurrentVideo: () => {
        const { playlist, activeIndex } = get();
        return playlist[activeIndex] || null;
      },

      addVideo: (videoFile: File, analysis: VideoAnalysis) => {
        const videoUrl = URL.createObjectURL(videoFile);
        const videoId = analysis.videoId || crypto.randomUUID();

        set((state) => ({
          playlist: [...state.playlist, { ...analysis, videoId }],
          videoSources: { ...state.videoSources, [videoId]: videoUrl }
        }));
      },

      setActiveIndex: (index: number) => {
        set({ activeIndex: Math.max(0, Math.min(index, get().playlist.length - 1)) });
      },

      nextScene: () => {
        const { activeIndex, playlist } = get();
        if (activeIndex < playlist.length - 1) {
          set({ activeIndex: activeIndex + 1 });
        }
      },

      prevScene: () => {
        const { activeIndex } = get();
        if (activeIndex > 0) {
          set({ activeIndex: activeIndex - 1 });
        }
      },

      toggleTranslation: () => {
        set((state) => ({ isTranslationVisible: !state.isTranslationVisible }));
      },

      recordWatchTime: (seconds: number, videoId: string) => {
        const { sessionStats, getVirtualDate } = get();
        const virtualDate = getVirtualDate();

        // Update local session stats
        set({
          sessionStats: {
            ...sessionStats,
            totalSecondsWatched: sessionStats.totalSecondsWatched + seconds
          }
        });

        // Sync with global progressStore (Activity Log)
        // Note: For high performance, we might want to debouncing this 
        // but for short sessions, direct sync is fine.
        const addActivityLog = useProgressStore.getState().addActivityLog;

        // Only log to global store if accumulated significant time (e.g., > 1 min)
        // or just rely on the manual "End Session" in a real app.
        // Here we simulate real-time XP gain.
      },

      markNodeComplete: (nodeId: string) => {
        set((state) => ({
          sessionStats: {
            ...state.sessionStats,
            nodesCompleted: state.sessionStats.nodesCompleted + 1
          }
        }));
      }
    }),
    {
      name: 'nihongo-nexus-immersion',
      storage: createJSONStorage(() => localStorage),
      // CRITICAL: Only persist the analysis and preferences, NOT the video sources
      partialize: (state) => ({
        playlist: state.playlist,
        isTranslationVisible: state.isTranslationVisible,
        autoScrollEnabled: state.autoScrollEnabled,
      }),
    }
  )
);

