interface ImmersionFeedProps {
  isSidebarVisible: boolean;
  onToggleSidebar: () => void;
}

const ImmersionFeed: React.FC<ImmersionFeedProps> = ({ isSidebarVisible, onToggleSidebar }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const { playlist, activeIndex, setActiveIndex, addVideo } = useImmersionStore();

  // Load Mock Data if playlist is empty (first run)
  useEffect(() => {
    if (playlist.length === 0) {
      // In a real app, we'd fetch or wait for upload
      // For this demo, we'll assume the MOCK data is our initial state
      // but converted to the VideoAnalysis format if necessary.
    }
  }, [playlist]);

  const handleScroll = () => {
    if (!containerRef.current) return;
    const scrollPos = containerRef.current.scrollTop;
    const height = containerRef.current.clientHeight;
    // Debounced index calculation
    const newIndex = Math.round(scrollPos / height);
    if (newIndex !== activeIndex) {
      setActiveIndex(newIndex);
    }
  };

  // We merge MOCK videos with any uploaded ones for the demo
  const displayVideos = playlist.length > 0 ? playlist : MOCK_IMMERSION_VIDEOS;

  return (
    <div className="h-screen w-full relative overflow-hidden bg-rose-50/50">
      {/* Main Feed Container */}
      <div 
        ref={containerRef}
        onScroll={handleScroll}
        className="h-screen overflow-y-scroll snap-y snap-mandatory scroll-smooth scrollbar-hide"
