/**
 * Headless Metadata Extraction
 * Uses a temporary video element to determine dimensions and duration.
 */
export const getVideoMetadata = (file: File): Promise<{ width: number; height: number; duration: number }> => {
  return new Promise((resolve, reject) => {
    const video = document.createElement('video');
    video.preload = 'metadata';

    const cleanup = () => {
      URL.revokeObjectURL(video.src);
      video.remove();
    };

    video.onloadedmetadata = () => {
      const dimensions = {
        width: video.videoWidth,
        height: video.videoHeight,
        duration: video.duration
      };
      cleanup();
      resolve(dimensions);
    };

    video.onerror = () => {
      cleanup();
      reject(new Error('Failed to load video metadata. The file might be corrupt or unsupported.'));
    };

    video.src = URL.createObjectURL(file);
  });
};

/**
 * Converts a browser File to a Base64 string for Gemini API ingestion.
 */
export const fileToBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => {
      const base64String = (reader.result as string).split(',')[1];
      resolve(base64String);
    };
    reader.onerror = (error) => reject(error);
  });
};

import { create } from 'zustand';
import { persist, createJSONStorage } from 'zustand/middleware';
import { VideoAnalysis } from '../types/immersionSchema';
import { format, addHours } from 'date-fns';
import { useProgressStore } from './progressStore';

interface SessionStats {
  totalSecondsWatched: number;
  nodesCompleted: number;
}

type LayoutMode = 'split' | 'stacked';

interface ImmersionState {
  // Persistent Data
  playlist: VideoAnalysis[];
  isTranslationVisible: boolean;
  autoScrollEnabled: boolean;
  layoutMode: LayoutMode;

  // In-Memory Data
  activeIndex: number;
  videoSources: Record<string, string>; 
  sessionStats: SessionStats;
  isAnalyzing: boolean;

  // Actions
  addAnalyzedVideo: (videoFile: File, analysis: VideoAnalysis) => void;
  setLayoutMode: (mode: LayoutMode) => void;
  nextScene: () => void;
  prevScene: () => void;
  setActiveIndex: (index: number) => void;
  toggleTranslation: () => void;
  recordWatchTime: (seconds: number, videoId: string) => void;
  setIsAnalyzing: (loading: boolean) => void;

  // Helpers
  getVirtualDate: () => string;
}

export const useImmersionStore = create<ImmersionState>()(
  persist(
    (set, get) => ({
      playlist: [],
      isTranslationVisible: false,
      autoScrollEnabled: true,
      layoutMode: 'split',
      activeIndex: 0,
      videoSources: {},
      isAnalyzing: false,
      sessionStats: {
        totalSecondsWatched: 0,
        nodesCompleted: 0,
      },

      getVirtualDate: () => {
        return format(addHours(new Date(), -6), 'yyyy-MM-dd');
      },

      setLayoutMode: (layoutMode) => set({ layoutMode }),

      setIsAnalyzing: (isAnalyzing) => set({ isAnalyzing }),

      addAnalyzedVideo: (videoFile, analysis) => {
        const videoUrl = URL.createObjectURL(videoFile);
        const videoId = analysis.videoId || crypto.randomUUID();

        set((state) => ({
          playlist: [{ ...analysis, videoId }, ...state.playlist],
          videoSources: { ...state.videoSources, [videoId]: videoUrl },
          activeIndex: 0 // Jump to the new video
        }));
      },

      setActiveIndex: (index) => {
        set({ activeIndex: Math.max(0, Math.min(index, get().playlist.length - 1)) });
      },

      nextScene: () => {
        const { activeIndex, playlist } = get();
        if (activeIndex < playlist.length - 1) {
          set({ activeIndex: activeIndex + 1 });
        }
      },

      prevScene: () => {
        const { activeIndex } = get();
        if (activeIndex > 0) {
          set({ activeIndex: activeIndex - 1 });
        }
      },

      toggleTranslation: () => {
        set((state) => ({ isTranslationVisible: !state.isTranslationVisible }));
      },

      recordWatchTime: (seconds, videoId) => {
        const { sessionStats } = get();
        set({
          sessionStats: {
            ...sessionStats,
            totalSecondsWatched: sessionStats.totalSecondsWatched + seconds
          }
        });

        // Sync with global progress if needed
        const addActivityLog = useProgressStore.getState().addActivityLog;
        // logic for logging XP could go here
      }
    }),
    {
      name: 'nihongo-nexus-immersion',
      storage: createJSONStorage(() => localStorage),
      partialize: (state) => ({
        playlist: state.playlist,
        isTranslationVisible: state.isTranslationVisible,
        autoScrollEnabled: state.autoScrollEnabled,
        layoutMode: state.layoutMode,
      }),
    }
  )
);

import React, { useState, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  Upload, 
  X, 
  Clapperboard, 
  Smartphone, 
  AlertCircle, 
  Loader2, 
  Sparkles, 
  CheckCircle2,
  FileVideo
} from 'lucide-react';
import { getVideoMetadata, fileToBase64 } from '../../utils/videoMetadata';
import { analyzeImmersionMedia } from '../../services/immersionService';
import { useImmersionStore } from '../../store/useImmersionStore';

interface UploadGatewayProps {
  isOpen: boolean;
  onClose: () => void;
}

const UploadGateway: React.FC<UploadGatewayProps> = ({ isOpen, onClose }) => {
  const [isDragging, setIsDragging] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [status, setStatus] = useState<{ msg: string; progress: number } | null>(null);
  const { addAnalyzedVideo, setLayoutMode, setIsAnalyzing } = useImmersionStore();
  const fileInputRef = useRef<HTMLInputElement>(null);

  const processFiles = async (files: FileList) => {
    if (files.length === 0) return;
    setError(null);

    try {
      // 1. Analyze the first file to determine mode
      const firstFile = files[0];
      const meta = await getVideoMetadata(firstFile);
      const isVertical = meta.height > meta.width;

      // 2. Decision Tree
      if (!isVertical && files.length > 1) {
        setError("Cinema Mode (Horizontal) only supports one video at a time for deep analysis.");
        return;
      }

      // Set Global Loading State
      setIsAnalyzing(true);
      setLayoutMode(isVertical ? 'split' : 'stacked');

      // 3. Sequential Processing (AI is resource intensive, don't parallelize too much)
      for (let i = 0; i < files.length; i++) {
        const file = files[i];
        setStatus({ msg: `Analyzing ${file.name}...`, progress: Math.round(((i + 1) / files.length) * 100) });

        const base64 = await fileToBase64(file);
        const analysis = await analyzeImmersionMedia(base64, file.type);

        addAnalyzedVideo(file, analysis);
      }

      setStatus({ msg: "Immersive chronicle complete!", progress: 100 });
      setTimeout(() => {
        onClose();
        setStatus(null);
        setIsAnalyzing(false);
      }, 1500);

    } catch (err: any) {
      console.error(err);
      setError(err.message || "The Neural Link failed to process this media.");
      setIsAnalyzing(false);
    }
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    processFiles(e.dataTransfer.files);
  };

  if (!isOpen) return null;

  return (
    <AnimatePresence>
      <div className="fixed inset-0 z-[200] flex items-center justify-center p-4">
        <motion.div 
          initial={{ opacity: 0 }} 
          animate={{ opacity: 1 }} 
          exit={{ opacity: 0 }}
          onClick={onClose}
          className="absolute inset-0 bg-rose-950/20 backdrop-blur-md"
        />

        <motion.div 
          initial={{ scale: 0.9, opacity: 0, y: 30 }} 
          animate={{ scale: 1, opacity: 1, y: 0 }} 
          exit={{ scale: 0.9, opacity: 0, y: 30 }}
          className="relative w-full max-w-xl bg-white rounded-[40px] shadow-2xl border border-rose-100 overflow-hidden flex flex-col"
        >
          {/* Header */}
          <div className="p-8 border-b border-rose-50 bg-rose-50/20 flex items-center justify-between">
            <div className="flex items-center gap-4">
              <div className="p-3 bg-white rounded-2xl text-rose-400 shadow-sm">
                <Upload className="w-6 h-6" />
              </div>
              <div>
                <h2 className="text-2xl font-bold font-coquette-header text-gray-800">Media Ingestion</h2>
                <p className="text-[10px] uppercase tracking-[0.2em] text-rose-400 font-bold mt-1">AI Transcription & Color-Mapping</p>
              </div>
            </div>
            <button onClick={onClose} className="p-2 rounded-full hover:bg-white text-gray-300 hover:text-rose-400 transition-colors">
              <X className="w-6 h-6" />
            </button>
          </div>

          <div className="p-8">
            {/* Main Drop Zone */}
            {!status ? (
              <div
                onDragOver={(e) => { e.preventDefault(); setIsDragging(true); }}
                onDragLeave={() => setIsDragging(false)}
                onDrop={handleDrop}
                onClick={() => fileInputRef.current?.click()}
                className={`
                  relative h-64 rounded-[32px] border-4 border-dashed transition-all duration-500 flex flex-col items-center justify-center cursor-pointer group
                  ${isDragging ? 'bg-rose-50 border-rose-400' : 'bg-gray-50/50 border-gray-100 hover:border-rose-200 hover:bg-rose-50/30'}
                `}
              >
                <input 
                  type="file" 
                  ref={fileInputRef} 
                  onChange={(e) => e.target.files && processFiles(e.target.files)} 
                  className="hidden" 
                  multiple 
                  accept="video/*"
                />

                <div className="p-5 rounded-full bg-white shadow-md text-rose-300 mb-6 group-hover:scale-110 transition-transform duration-500">
                  <FileVideo className="w-10 h-10" />
                </div>

                <h3 className="text-xl font-bold font-coquette-header text-gray-700">Drop your immersion clips</h3>
                <p className="text-sm font-coquette-body text-gray-400 italic mt-2">MP4, MOV, or WebM accepted</p>

                {/* Smart Badge Previews */}
                <div className="absolute bottom-6 flex gap-4">
                  <div className="flex items-center gap-2 px-3 py-1.5 rounded-full bg-white/80 border border-gray-100 text-[9px] font-black uppercase text-gray-400">
                    <Smartphone className="w-3 h-3" /> Vertical Batch
                  </div>
                  <div className="flex items-center gap-2 px-3 py-1.5 rounded-full bg-white/80 border border-gray-100 text-[9px] font-black uppercase text-gray-400">
                    <Clapperboard className="w-3 h-3" /> Cinema Single
                  </div>
                </div>
              </div>
            ) : (
              // Processing State
              <div className="h-64 flex flex-col items-center justify-center text-center space-y-6">
                <div className="relative">
                  <div className="w-24 h-24 border-4 border-rose-100 border-t-rose-400 rounded-full animate-spin" />
                  <div className="absolute inset-0 flex items-center justify-center text-rose-400">
                    {status.progress === 100 ? <CheckCircle2 className="w-10 h-10 text-emerald-400" /> : <Sparkles className="w-8 h-8 animate-pulse" />}
                  </div>
                </div>
                <div>
                   <h3 className="text-2xl font-bold font-coquette-header text-gray-800">{status.msg}</h3>
                   <div className="w-64 h-2 bg-gray-100 rounded-full mt-4 overflow-hidden">
                      <motion.div 
                        initial={{ width: 0 }} 
                        animate={{ width: `${status.progress}%` }} 
                        className="h-full bg-rose-400"
                      />
                   </div>
                   <p className="text-[10px] font-black uppercase tracking-widest text-rose-300 mt-3">Consulting the Immersion Engine</p>
                </div>
              </div>
            )}

            {/* Error Message */}
            <AnimatePresence>
              {error && (
                <motion.div 
                  initial={{ opacity: 0, y: 10 }}
                  animate={{ opacity: 1, y: 0 }}
                  className="mt-6 p-4 rounded-2xl bg-red-50 border border-red-100 flex items-start gap-3 text-red-500"
                >
                  <AlertCircle className="w-5 h-5 shrink-0 mt-0.5" />
                  <p className="text-xs font-bold leading-relaxed">{error}</p>
                </motion.div>
              )}
            </AnimatePresence>
          </div>

          {/* Footer Info */}
          <div className="p-6 bg-gray-50/50 border-t border-rose-50 text-center">
             <p className="text-[9px] text-gray-400 font-medium leading-relaxed max-w-sm mx-auto">
               Note: AI analysis splits Japanese morphemes and synchronizes them with English concepts. This may take 15-30 seconds per minute of video.
             </p>
          </div>
        </motion.div>
      </div>
    </AnimatePresence>
  );
};

