import React, { useEffect, useRef, useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { ImmersionVideo } from '../../types';
import TranscriptStream from './TranscriptStream';
import { 
  Clapperboard, 
  Maximize2, 
  SkipForward, 
  Plus, 
  FileVideo, 
  Volume2, 
  VolumeX,
  Play as PlayIcon,
  Pause as PauseIcon
} from 'lucide-react';
import { useImmersionStore } from '../../store/useImmersionStore';
import UploadGateway from './UploadGateway';

interface ImmersionStageProps {
  video: ImmersionVideo | any;
  isActive: boolean;
  index: number;
  total: number;
}

const ImmersionStage: React.FC<ImmersionStageProps> = ({ video, isActive, index, total }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const [isUploadOpen, setIsUploadOpen] = useState(false);
  const [isMuted, setIsMuted] = useState(true);
  const [isPaused, setIsPaused] = useState(false);
  const [showPlayStateOverlay, setShowPlayStateOverlay] = useState(false);
  const overlayTimerRef = useRef<number | null>(null);

  const { videoSources, recordWatchTime, nextScene, layoutMode } = useImmersionStore();

  // Safe Access Checks
  if (!video) {
    return (
      <div className="h-screen w-full flex flex-col items-center justify-center bg-rose-50/20">
         <div className="p-8 bg-white rounded-[40px] shadow-xl border border-rose-100 flex flex-col items-center gap-4 text-center">
            <div className="w-16 h-16 rounded-full bg-rose-50 flex items-center justify-center text-rose-300">
               <FileVideo className="w-8 h-8" />
            </div>
            <h2 className="font-coquette-header text-2xl text-gray-800">Scene Not Found</h2>
            <p className="font-coquette-body text-gray-400 italic">Please ingest media to begin the session.</p>
         </div>
      </div>
    );
  }

  const videoSrc = videoSources[video.videoId || video.id] || video.videoUrl;

  const dialogueData = video.nodes || video.dialogue || [];

  // Manage Playback based on isActive
  useEffect(() => {
    if (videoRef.current) {
      if (isActive) {
        videoRef.current.play().catch(e => console.warn("Autoplay failed:", e));
        setIsPaused(false);
      } else {
        videoRef.current.pause();
        setIsPaused(true);
      }
    }
  }, [isActive]);

  // Record watch time
  useEffect(() => {
    let interval: number;
    if (isActive && videoRef.current) {
      interval = window.setInterval(() => {
        if (!videoRef.current?.paused) {
          recordWatchTime(5, video.videoId || video.id);
        }
      }, 5000);
    }
    return () => clearInterval(interval);
  }, [isActive, video.videoId, video.id, recordWatchTime]);

  const isStacked = layoutMode === 'stacked';

  const toggleAudio = () => {
    setIsMuted(!isMuted);
    if (videoRef.current) {
      videoRef.current.muted = !isMuted;
    }
  };

  const togglePlay = () => {
    if (!videoRef.current) return;

    if (videoRef.current.paused) {
      videoRef.current.play();
      setIsPaused(false);
    } else {
      videoRef.current.pause();
      setIsPaused(true);
    }

    // Visual feedback overlay
    setShowPlayStateOverlay(true);
    if (overlayTimerRef.current) window.clearTimeout(overlayTimerRef.current);
    overlayTimerRef.current = window.setTimeout(() => {
      setShowPlayStateOverlay(false);
    }, 800);
  };

  return (
    <div className="h-screen w-full snap-start flex flex-col bg-[#fffcfc]">
      {/* Unified Compact Toolbar */}
      <header className="h-[60px] w-full border-b border-rose-100 bg-white px-8 flex items-center justify-between shrink-0 z-[60]">
         <div className="flex items-center gap-3">
            <div className="p-1.5 rounded-lg bg-rose-50 text-coquette-accent">
               <Clapperboard className="w-4 h-4" />
            </div>
            <div className="flex flex-col">
               <h1 className="text-base font-coquette-header text-coquette-text leading-none tracking-tight">Immersion Theater</h1>
               <span className="text-[8px] font-black text-rose-300 uppercase tracking-[0.2em] mt-0.5">
                  {isStacked ? 'Cinema Mode' : 'TikTok Mode'}
               </span>
            </div>
         </div>

         <div className="flex items-center gap-4 lg:gap-8">
            <button 
              onClick={() => setIsUploadOpen(true)}
              className="flex items-center gap-2 px-4 py-1.5 rounded-full bg-white border border-rose-100 text-rose-400 hover:bg-rose-50 transition-all shadow-sm group"
            >
               <Plus className="w-3.5 h-3.5 group-hover:rotate-90 transition-transform" />
               <span className="text-[10px] font-bold uppercase tracking-widest">Ingest Media</span>
            </button>

            <div className="h-8 w-px bg-rose-50 hidden sm:block" />

            <div className="flex items-center gap-5">
               <div className="flex flex-col items-end min-w-[60px]">
                  <span className="text-[8px] font-black text-coquette-subtext uppercase tracking-widest">Scene</span>
                  <span className="text-[10px] font-bold text-coquette-text">{index + 1} of {total}</span>
               </div>
            </div>
         </div>
      </header>

      {/* Main Container Unit */}
      <div className={`flex-1 flex overflow-hidden bg-[#fffcfc] ${isStacked ? 'flex-col' : 'flex-col lg:flex-row'}`}>

        {/* Video Side */}
        <div className={`
          flex flex-col gap-5 overflow-y-auto custom-scrollbar transition-all duration-700
          ${isStacked ? 'w-full h-[60%] lg:h-[70%] p-4 lg:p-6 items-center' : 'w-full lg:w-[48%] h-full p-6 lg:p-10'}
        `}>
          <div className={`
            flex flex-col rounded-[24px] overflow-hidden shadow-2xl border border-rose-100 bg-white shrink-0
            ${isStacked ? 'max-w-5xl w-full h-full' : 'w-full'}
          `}>
            <div className={`relative bg-black group ${isStacked ? 'flex-1' : 'aspect-video'}`}>
              <video
                ref={videoRef}
                src={videoSrc}
                loop
                muted={isMuted}
                playsInline
                onClick={togglePlay}
                className={`w-full h-full object-contain grayscale-[0.1] sepia-[0.05] transition-opacity duration-500 cursor-pointer ${isActive ? 'opacity-100' : 'opacity-0'}`}
              />

              <div className="absolute inset-0 bg-black/5 group-hover:bg-transparent transition-colors pointer-events-none" />

              {/* Play/Pause Animated Overlay */}
              <AnimatePresence>
                {showPlayStateOverlay && (
                  <motion.div 
                    initial={{ scale: 0.5, opacity: 0 }}
                    animate={{ scale: 1.2, opacity: 0.8 }}
                    exit={{ scale: 1.5, opacity: 0 }}
                    className="absolute inset-0 flex items-center justify-center pointer-events-none"
                  >
                    <div className="p-6 rounded-full bg-white/20 backdrop-blur-md text-white">
                      {isPaused ? <PauseIcon className="w-12 h-12" /> : <PlayIcon className="w-12 h-12" />}
                    </div>
                  </motion.div>
                )}
              </AnimatePresence>

              <div className="absolute bottom-4 right-4 flex gap-2">
                  <button className="p-2 bg-white/20 backdrop-blur-md rounded-full text-white hover:bg-white/40 transition-colors shadow-sm">
                    <Maximize2 className="w-4 h-4" />
                  </button>
              </div>
            </div>

            <div className="p-4 px-6 flex items-center justify-between bg-white/80 shrink-0">
              <div className="flex items-center gap-4">
                <button 
                  onClick={toggleAudio}
                  className={`
                    relative w-12 h-12 rounded-full flex items-center justify-center transition-all duration-500 shadow-lg group/audio
                    ${isMuted ? 'bg-white border border-rose-100 text-rose-300' : 'bg-coquette-accent text-white scale-110 shadow-rose-200'}
                  `}
                  title={isMuted ? "Turn Audio On" : "Mute Audio"}
                >
                  <AnimatePresence mode="wait">
                    <motion.div
                      key={isMuted ? 'muted' : 'unmuted'}
                      initial={{ scale: 0, rotate: -45 }}
                      animate={{ scale: 1, rotate: 0 }}
                      exit={{ scale: 0, rotate: 45 }}
                      className="absolute"
                    >
                      {isMuted ? <VolumeX className="w-5 h-5" /> : <Volume2 className="w-5 h-5" />}
                    </motion.div>
                  </AnimatePresence>

                  {!isMuted && (
                    <motion.div 
                      animate={{ scale: [1, 1.5], opacity: [0.5, 0] }}
                      transition={{ duration: 1.5, repeat: Infinity }}
                      className="absolute inset-0 rounded-full bg-coquette-accent"
                    />
                  )}
                </button>

                <div className="flex flex-col">
                  <span className="text-[8px] font-black uppercase text-rose-300 tracking-[0.3em] mb-0.5">Now Playing</span>
                  <span className="text-xs font-bold font-coquette-body text-coquette-subtext italic truncate max-w-[200px] lg:max-w-[300px]">
                    {video.title}
                  </span>
                </div>
              </div>

              <div className="flex items-center gap-3">
                <button 
                  onClick={() => nextScene()}
                  className="flex items-center gap-2 px-5 py-2 rounded-full bg-coquette-accent text-white font-black text-[10px] uppercase tracking-widest shadow-md hover:bg-[#ff9eb0] transition-all transform active:scale-95"
                >
                  <SkipForward className="w-3 h-3" /> Next Scene
                </button>
              </div>
            </div>
          </div>
        </div>

        {/* Transcript Side */}
        <div className={`
          flex-1 h-full lg:border-l border-rose-100 shadow-[-15px_0_40px_rgba(244,172,183,0.03)] bg-[#fffcfc]/40 backdrop-blur-sm
          ${isStacked ? 'max-h-[40%] lg:max-h-[30%]' : ''}
        `}>
           <TranscriptStream dialogue={dialogueData} />
        </div>
      </div>

      <UploadGateway isOpen={isUploadOpen} onClose={() => setIsUploadOpen(false)} />
    </div>
  );
};

export default ImmersionStage;

import React, { useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { DialogueLine } from '../../types';
import { ImmersionToken, TokenType } from '../../types/immersionSchema';
import { ScrollText } from 'lucide-react';

interface TranscriptStreamProps {
  nodes?: (DialogueLine | any)[];
  activeNodeId: string | null;
  onSeek: (timestamp: number) => void;
  isTranslationVisible: boolean;
}

const TokenChip: React.FC<{ 
  token: ImmersionToken; 
  isEnglish?: boolean;
}> = ({ token, isEnglish = false }) => {
  const isPunctuation = token.type === TokenType.PUNCTUATION;
  const isGrammar = token.type === TokenType.GRAMMAR;

  return (
    <span className={`inline-flex px-0.5 rounded ${isPunctuation ? 'text-gray-300' : ''}`}>
      <span className={`
        font-coquette-rounded leading-tight
        ${isEnglish ? 'text-[11px] md:text-xs' : 'text-base md:text-lg'}
        ${isGrammar ? 'text-rose-400 font-medium' : (isEnglish ? 'text-gray-500 font-medium' : 'font-bold text-coquette-text')}
      `}>
        {token.text}
      </span>
    </span>
  );
};

const TranscriptLine: React.FC<{ 
  line: DialogueLine;
  isActive: boolean;
  isTranslationVisible: boolean;
  onSeek: (timestamp: number) => void;
}> = ({ line, isActive, isTranslationVisible, onSeek }) => {
  const lineRef = useRef<HTMLDivElement>(null);

  // Auto-scroll to active line
  useEffect(() => {
    if (isActive && lineRef.current) {
      lineRef.current.scrollIntoView({ behavior: 'smooth', block: 'center' });
    }
  }, [isActive]);

  return (
    <div 
      ref={lineRef}
      className={`mb-4 transition-all duration-500 rounded-[24px] ${isActive ? 'scale-[1.02]' : 'opacity-60 hover:opacity-100'}`}
    >
      <motion.div
        onClick={() => onSeek(line.timestampStart)}
        animate={{ 
          backgroundColor: isActive ? 'rgba(255, 255, 255, 0.9)' : 'rgba(255, 255, 255, 0)',
          borderColor: isActive ? '#fde2e4' : 'rgba(253, 226, 228, 0)',
          boxShadow: isActive ? '0 10px 30px -10px rgba(244, 172, 183, 0.2)' : 'none'
        }}
        className="w-full text-left py-4 px-6 rounded-[24px] border-2 cursor-pointer transition-shadow"
      >
        <div className="flex flex-col gap-2">
          {/* Japanese Token Stream */}
          <div className="flex flex-wrap items-end gap-x-0.5">
            {line.japanese.map((t, i) => (
              <TokenChip key={i} token={t} />
            ))}
          </div>

          {/* English Stream - Controlled by Parent */}
          <AnimatePresence>
            {isActive && isTranslationVisible && (
              <motion.div
                initial={{ height: 0, opacity: 0 }}
                animate={{ height: 'auto', opacity: 1 }}
                exit={{ height: 0, opacity: 0 }}
                transition={{ duration: 0.3 }}
                className="overflow-hidden"
              >
                <div className="flex flex-wrap items-center gap-x-0.5 border-l-2 border-rose-200/50 pl-4 mt-2 mb-1">
                  {line.english.map((t, i) => (
                    <TokenChip key={i} token={t} isEnglish />
                  ))}
                </div>
              </motion.div>
            )}
          </AnimatePresence>
        </div>
      </motion.div>
    </div>
  );
};

const TranscriptSkeleton = () => (
  <div className="space-y-8 animate-pulse mt-4">
    {[1, 2, 3].map(i => (
      <div key={i} className="space-y-3 px-6">
        <div className="flex gap-2">
          <div className="h-7 w-32 bg-rose-100/40 rounded-lg" />
          <div className="h-7 w-20 bg-rose-100/20 rounded-lg" />
        </div>
        <div className="h-4 w-48 bg-gray-100/50 rounded-lg" />
      </div>
    ))}
  </div>
);

const TranscriptStream: React.FC<TranscriptStreamProps> = ({ nodes, activeNodeId, onSeek, isTranslationVisible }) => {
  const hasContent = nodes && nodes.length > 0;

  return (
    <div className="h-full flex flex-col overflow-hidden relative">
      <div className="flex-1 overflow-y-auto p-4 lg:p-8 scrollbar-thin scrollbar-thumb-rose-100 bg-[url('https://www.transparenttextures.com/patterns/cream-paper.png')]">
        <div className="max-w-2xl mx-auto py-10">
          {!hasContent ? (
             <div className="flex flex-col items-center justify-center py-20 text-center">
                <div className="p-5 rounded-full bg-white shadow-sm border border-rose-50 text-rose-200 mb-6">
                  <ScrollText className="w-10 h-10" />
                </div>
                <h3 className="font-coquette-header text-xl text-gray-700 font-bold mb-2">Analyzing Dialogue...</h3>
                <TranscriptSkeleton />
             </div>
          ) : (
            nodes.map((line) => (
              <TranscriptLine 
                key={line.id} 
                line={line} 
                isActive={activeNodeId === line.id}
                isTranslationVisible={isTranslationVisible}
                onSeek={onSeek}
              />
            ))
          )}
          <div className="h-40" />
        </div>
      </div>
    </div>
  );
};

export default TranscriptStream;

