const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * The "Immersion Engine"
 * Analyzes audio/video data to produce conceptual color-coded transcripts.
 */
export const analyzeImmersionMedia = async (base64Data: string, mimeType: string, duration?: number): Promise<VideoAnalysis> => {
  const durationHint = duration ? `The video is exactly ${duration.toFixed(2)} seconds long.` : "";

  const prompt = `
    Analyze the provided media and provide a STICKY-SYNC transcript. 
    ${durationHint}

    CRITICAL TRANSCRIPTION RULES (VERBATIM MODE):
    1. STRICTLY VERBATIM: You must transcribe EXACTLY what is spoken. Include all filler words (eto, ano, nanka), stutters, and false starts.
    2. NO CLEANING: Do not correct grammar or remove hesitant sounds. The text must match the audio 1:1.
    3. FULL COVERAGE: You must analyze the ENTIRE duration from 0:00.00 to the very last second. Do not stop early.
    4. PRECISION: Use sub-second (0.01s) precision for timestampStart and timestampEnd. 

    Linguistic Rules:
    1. Morpheme Splitting (Japanese): Split verbs/adjectives into Root (CONTENT) and Conjugation (GRAMMAR).
       Ex: "Tabetakatta" -> [Tabe (CONTENT)] + [ta (GRAMMAR)] + [katta (GRAMMAR)].
    2. Semantic Linking (groupId): Assign a unique integer ID to distinct concepts. 
       If JP "Ringo" maps to EN "Apple", they share the same groupId.
    3. Type Logic:
       CONTENT: Nouns, Verb Roots, Adjective Roots, Adverbs.
       GRAMMAR: Particles, Copulas, Verb Endings, Connectors.
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: [
      {
        inlineData: {
          data: base64Data,
          mimeType: mimeType,
        },
      },
      {
        text: prompt,
      },
    ],
    config: {
      responseMimeType: 'application/json',
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          nodes: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                id: { type: Type.STRING },
                timestampStart: { type: Type.NUMBER },
                timestampEnd: { type: Type.NUMBER },
                speaker: { type: Type.STRING },
                japanese: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      text: { type: Type.STRING },
                      romaji: { type: Type.STRING },
                      type: { type: Type.STRING },
                      groupId: { type: Type.INTEGER }
                    },
                    required: ["text", "type", "groupId"]
                  }
                },
                english: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      text: { type: Type.STRING },
                      type: { type: Type.STRING },
                      groupId: { type: Type.INTEGER }
                    },
                    required: ["text", "type", "groupId"]
                  }
                }
              },
              required: ["id", "timestampStart", "timestampEnd", "speaker", "japanese", "english"]
            }
          }
        },
        required: ["nodes"]
      }
    }
  });

  if (response.text) {
    const parsed = JSON.parse(response.text);
    return parsed as VideoAnalysis;
  }
  throw new Error("Failed to analyze media");
};

/**
 * The "Deep Dive Sensei"
 */
export const explainToken = async (contextSentence: string, targetPhrase: string): Promise<ExplanationCard> => {
  const prompt = `
    You are the "Sensei" for Nihongo Nexus. Provide a "Gold Standard" grammatical breakdown.

    Context Sentence: "${contextSentence}"
    Target Phrase: "${targetPhrase}"

    TASKS:
    1. Explode the word into atomic parts (Base form + Conjugations + Particles).
    2. Explain nuance based on the context.

    Return strictly JSON matching the schema.
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: 'application/json',
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          headword: {
            type: Type.OBJECT,
            properties: {
              text: { type: Type.STRING },
              romaji: { type: Type.STRING },
              basicMeaning: { type: Type.STRING }
            },
            required: ["text", "romaji", "basicMeaning"]
          },
          analysis: {
            type: Type.OBJECT,
            properties: {
              baseForm: { type: Type.STRING },
              conjugationPath: { type: Type.ARRAY, items: { type: Type.STRING } },
              breakdown: { type: Type.STRING }
            },
            required: ["baseForm", "conjugationPath", "breakdown"]
          },
          particle: {
            type: Type.OBJECT,
            properties: {
              text: { type: Type.STRING },
              function: { type: Type.STRING }
            }
          },
          nuance: {
            type: Type.OBJECT,
            properties: {
              jlptLevel: { type: Type.STRING },
              explanation: { type: Type.STRING }
            },
            required: ["jlptLevel", "explanation"]
          },
          naturalTranslation: { type: Type.STRING }
        },
        required: ["headword", "analysis", "nuance", "naturalTranslation"]
      }
    }
  });

  if (response.text) {
    return JSON.parse(response.text) as ExplanationCard;
  }
  throw new Error("Sensei failed to explain");
};

import React, { useState, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  Upload, 
  X, 
  Clapperboard, 
  Smartphone, 
  AlertCircle, 
  Sparkles, 
  CheckCircle2,
  FileVideo
} from 'lucide-react';
import { getVideoMetadata, fileToBase64 } from '../../utils/videoMetadata';
import { analyzeImmersionMedia } from '../../services/immersionService';
import { useImmersionStore } from '../../store/useImmersionStore';

interface UploadGatewayProps {
  isOpen: boolean;
  onClose: () => void;
}

const UploadGateway: React.FC<UploadGatewayProps> = ({ isOpen, onClose }) => {
  const [isDragging, setIsDragging] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [status, setStatus] = useState<{ msg: string; progress: number } | null>(null);
  const { addAnalyzedVideo, setLayoutMode, setIsAnalyzing } = useImmersionStore();
  const fileInputRef = useRef<HTMLInputElement>(null);

  const processFiles = async (files: FileList) => {
    if (files.length === 0) return;
    setError(null);

    try {
      const firstFile = files[0];
      const meta = await getVideoMetadata(firstFile);
      const isVertical = meta.height > meta.width;

      if (!isVertical && files.length > 1) {
        setError("Cinema Mode (Horizontal) only supports one video at a time for deep analysis.");
        return;
      }

      setIsAnalyzing(true);
      setLayoutMode(isVertical ? 'split' : 'stacked');

      for (let i = 0; i < files.length; i++) {
        const file = files[i];
        const fileMeta = await getVideoMetadata(file); // Get precise duration for each

        setStatus({ msg: `Analyzing ${file.name}...`, progress: Math.round(((i + 1) / files.length) * 100) });

        const base64 = await fileToBase64(file);
        // Pass duration to ensure full coverage
        const analysis = await analyzeImmersionMedia(base64, file.type, fileMeta.duration);

        addAnalyzedVideo(file, analysis);
      }

      setStatus({ msg: "Immersive chronicle complete!", progress: 100 });
      setTimeout(() => {
        onClose();
        setStatus(null);
        setIsAnalyzing(false);
      }, 1500);

    } catch (err: any) {
      console.error(err);
      setError(err.message || "The Neural Link failed to process this media.");
      setIsAnalyzing(false);
    }
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    processFiles(e.dataTransfer.files);
  };

  if (!isOpen) return null;

  return (
    <AnimatePresence>
      <div className="fixed inset-0 z-[200] flex items-center justify-center p-4">
        <motion.div 
          initial={{ opacity: 0 }} 
          animate={{ opacity: 1 }} 
          exit={{ opacity: 0 }}
          onClick={onClose}
          className="absolute inset-0 bg-rose-950/20 backdrop-blur-sm"
        />

        <motion.div 
          initial={{ scale: 0.9, opacity: 0, y: 30 }} 
          animate={{ scale: 1, opacity: 1, y: 0 }} 
          exit={{ scale: 0.9, opacity: 0, y: 30 }}
          className="relative w-full max-w-xl bg-white rounded-[40px] shadow-2xl border border-rose-100 overflow-hidden flex flex-col"
        >
          {/* Header */}
          <div className="p-8 border-b border-rose-50 bg-rose-50/20 flex items-center justify-between">
            <div className="flex items-center gap-4">
              <div className="p-3 bg-white rounded-2xl text-rose-400 shadow-sm">
                <Upload className="w-6 h-6" />
              </div>
              <div>
                <h2 className="text-2xl font-bold font-coquette-header text-gray-800">Media Ingestion</h2>
                <p className="text-[10px] uppercase tracking-[0.2em] text-rose-400 font-bold mt-1">AI Transcription & Color-Mapping</p>
              </div>
            </div>
            <button onClick={onClose} className="p-2 rounded-full hover:bg-white text-gray-300 hover:text-rose-400 transition-colors">
              <X className="w-6 h-6" />
            </button>
          </div>

          <div className="p-8">
            {!status ? (
              <div
                onDragOver={(e) => { e.preventDefault(); setIsDragging(true); }}
                onDragLeave={() => setIsDragging(false)}
                onDrop={handleDrop}
                onClick={() => fileInputRef.current?.click()}
                className={`
                  relative h-64 rounded-[32px] border-4 border-dashed transition-all duration-500 flex flex-col items-center justify-center cursor-pointer group
                  ${isDragging ? 'bg-rose-50 border-rose-400' : 'bg-gray-50/50 border-gray-100 hover:border-rose-200 hover:bg-rose-50/30'}
                `}
              >
                <input 
                  type="file" 
                  ref={fileInputRef} 
                  onChange={(e) => e.target.files && processFiles(e.target.files)} 
                  className="hidden" 
                  multiple 
                  accept="video/*"
                />

                <div className="p-5 rounded-full bg-white shadow-md text-rose-300 mb-6 group-hover:scale-110 transition-transform duration-500">
                  <FileVideo className="w-10 h-10" />
                </div>

                <h3 className="text-xl font-bold font-coquette-header text-gray-700">Drop your immersion clips</h3>
                <p className="text-sm font-coquette-body text-gray-400 italic mt-2">MP4, MOV, or WebM accepted</p>

                <div className="absolute bottom-6 flex gap-4">
                  <div className="flex items-center gap-2 px-3 py-1.5 rounded-full bg-white/80 border border-gray-100 text-[9px] font-black uppercase text-gray-400">
                    <Smartphone className="w-3 h-3" /> Vertical Batch
                  </div>
                  <div className="flex items-center gap-2 px-3 py-1.5 rounded-full bg-white/80 border border-gray-100 text-[9px] font-black uppercase text-gray-400">
                    <Clapperboard className="w-3 h-3" /> Cinema Single
                  </div>
                </div>
              </div>
            ) : (
              <div className="h-64 flex flex-col items-center justify-center text-center space-y-6">
                <div className="relative">
                  <div className="w-24 h-24 border-4 border-rose-100 border-t-rose-400 rounded-full animate-spin" />
                  <div className="absolute inset-0 flex items-center justify-center text-rose-400">
                    {status.progress === 100 ? <CheckCircle2 className="w-10 h-10 text-emerald-400" /> : <Sparkles className="w-8 h-8 animate-pulse" />}
                  </div>
                </div>
                <div>
                   <h3 className="text-2xl font-bold font-coquette-header text-gray-800">{status.msg}</h3>
                   <div className="w-64 h-2 bg-gray-100 rounded-full mt-4 overflow-hidden">
                      <motion.div 
                        initial={{ width: 0 }} 
                        animate={{ width: `${status.progress}%` }} 
                        className="h-full bg-rose-400"
                      />
                   </div>
                   <p className="text-[10px] font-black uppercase tracking-widest text-rose-300 mt-3">Consulting the Immersion Engine</p>
                </div>
              </div>
            )}

            <AnimatePresence>
              {error && (
                <motion.div 
                  initial={{ opacity: 0, y: 10 }}
                  animate={{ opacity: 1, y: 0 }}
                  className="mt-6 p-4 rounded-2xl bg-red-50 border border-red-100 flex items-start gap-3 text-red-500"
                >
                  <AlertCircle className="w-5 h-5 shrink-0 mt-0.5" />
                  <p className="text-xs font-bold leading-relaxed">{error}</p>
                </motion.div>
              )}
            </AnimatePresence>
          </div>

          <div className="p-6 bg-gray-50/50 border-t border-rose-50 text-center">
             <p className="text-[9px] text-gray-400 font-medium leading-relaxed max-w-sm mx-auto">
               Verbatim Mode Enabled: Full duration transcription with millisecond sync.
             </p>
          </div>
        </motion.div>
      </div>
    </AnimatePresence>
  );
};

export default UploadGateway;

