import React, { useEffect, useRef, useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { DialogueLine } from '../../types';
import { ImmersionToken, TokenType } from '../../types/immersionSchema';
import { ScrollText, Navigation2 } from 'lucide-react';

interface TranscriptStreamProps {
  nodes?: (DialogueLine | any)[];
  activeNodeId: string | null;
  onSeek: (timestamp: number) => void;
  isTranslationVisible: boolean;
}

const TokenChip: React.FC<{ 
  token: ImmersionToken; 
  isEnglish?: boolean;
  isActive: boolean;
  onTokenClick: (groupId: number) => void;
}> = ({ token, isEnglish = false, isActive, onTokenClick }) => {
  const isPunctuation = token.type === TokenType.PUNCTUATION;
  const isGrammar = token.type === TokenType.GRAMMAR;

  // Concept mapping logic: Only highlight if groupId is valid (non-zero)
  const canHighlight = token.groupId !== 0;

  return (
    <motion.span 
      onClick={() => canHighlight && onTokenClick(token.groupId)}
      className={`
        inline-flex px-1 py-0.5 rounded-md transition-all duration-200 cursor-pointer
        ${isActive ? 'bg-emerald-50 text-emerald-600 ring-1 ring-emerald-100 shadow-sm z-10' : ''}
        ${!isActive && isPunctuation ? 'text-gray-300' : ''}
        ${!canHighlight ? 'cursor-default' : 'hover:bg-rose-50/50'}
      `}
    >
      <span className={`
        font-coquette-rounded leading-tight select-none
        ${isEnglish ? 'text-[11px] md:text-xs' : 'text-base md:text-lg'}
        ${!isActive && isGrammar ? 'text-rose-400 font-medium' : ''}
        ${!isActive && !isGrammar && !isPunctuation ? (isEnglish ? 'text-gray-500 font-medium' : 'font-bold text-coquette-text') : ''}
        ${isActive ? 'font-bold' : ''}
      `}>
        {token.text}
      </span>
    </motion.span>
  );
};

const TranscriptLine: React.FC<{ 
  line: DialogueLine;
  isActive: boolean;
  isTranslationVisible: boolean;
  onSeek: (timestamp: number) => void;
  activeGroupId: number | null;
  onTokenClick: (groupId: number) => void;
}> = ({ line, isActive, isTranslationVisible, onSeek, activeGroupId, onTokenClick }) => {
  const lineRef = useRef<HTMLDivElement>(null);

  // Auto-scroll to active line
  useEffect(() => {
    if (isActive && lineRef.current) {
      lineRef.current.scrollIntoView({ behavior: 'smooth', block: 'center' });
    }
  }, [isActive]);

  return (
    <div 
      ref={lineRef}
      className={`mb-4 flex gap-3 transition-all duration-500 ${isActive ? 'scale-[1.02]' : 'opacity-60'}`}
    >
      {/* Navigation (The Sidebar / Gutter) */}
      <div className="flex flex-col items-center pt-2">
        <button
          onClick={() => onSeek(line.timestampStart)}
          title="Jump video to this line"
          className={`
            w-1.5 flex-1 rounded-full transition-all duration-300 group relative
            ${isActive ? 'bg-rose-300 shadow-[0_0_8px_rgba(244,172,183,0.5)]' : 'bg-stone-200 hover:bg-rose-200'}
          `}
        >
          <div className="absolute left-1/2 -translate-x-1/2 -top-1 opacity-0 group-hover:opacity-100 transition-opacity">
             <Navigation2 className="w-2.5 h-2.5 text-rose-400 fill-current" />
          </div>
        </button>
      </div>

      {/* Dialogue Content */}
      <motion.div
        animate={{ 
          backgroundColor: isActive ? 'rgba(255, 255, 255, 0.95)' : 'rgba(255, 255, 255, 0.4)',
          borderColor: isActive ? '#fde2e4' : 'transparent',
          boxShadow: isActive ? '0 15px 35px -10px rgba(244, 172, 183, 0.15)' : 'none'
        }}
        className="flex-1 text-left py-4 px-6 rounded-[24px] border-2 transition-shadow"
      >
        <div className="flex flex-col gap-2">
          {/* Japanese Token Stream */}
          <div className="flex flex-wrap items-end gap-x-0.5">
            {line.japanese.map((t, i) => (
              <TokenChip 
                key={i} 
                token={t} 
                isActive={activeGroupId === t.groupId && t.groupId !== 0}
                onTokenClick={onTokenClick}
              />
            ))}
          </div>

          {/* English Stream - The Drawer */}
          <AnimatePresence>
            {isActive && isTranslationVisible && (
              <motion.div
                initial={{ height: 0, opacity: 0 }}
                animate={{ height: 'auto', opacity: 1 }}
                exit={{ height: 0, opacity: 0 }}
                transition={{ duration: 0.3, ease: "circOut" }}
                className="overflow-hidden"
              >
                <div className="flex flex-wrap items-center gap-x-0.5 border-l-2 border-emerald-100/50 pl-4 mt-2 mb-1 py-1">
                  {line.english.map((t, i) => (
                    <TokenChip 
                      key={i} 
                      token={t} 
                      isEnglish 
                      isActive={activeGroupId === t.groupId && t.groupId !== 0}
                      onTokenClick={onTokenClick}
                    />
                  ))}
                </div>
              </motion.div>
            )}
          </AnimatePresence>
        </div>
      </motion.div>
    </div>
  );
};

const TranscriptSkeleton = () => (
  <div className="space-y-8 animate-pulse mt-4">
