           <div className="w-px h-3 bg-stone-200" />
           <div className="flex items-center gap-1.5">
              <div className="w-2 h-2 bg-emerald-400 rounded-sm" /> Word Sync
           </div>
        </div>
      </div>
    </div>
  );
};

