import React, { useRef, useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { MOCK_IMMERSION_VIDEOS } from '../../data/immersionData';
import ImmersionStage from './ImmersionStage';
import { ChevronDown, Upload, Sparkles } from 'lucide-react';
import { useImmersionStore } from '../../store/useImmersionStore';

interface ImmersionFeedProps {
  isSidebarVisible: boolean;
  onToggleSidebar: () => void;
}

const ImmersionFeed: React.FC<ImmersionFeedProps> = ({ isSidebarVisible, onToggleSidebar }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const { playlist, activeIndex, setActiveIndex } = useImmersionStore();

  const handleScroll = () => {
    if (!containerRef.current) return;
    const scrollPos = containerRef.current.scrollTop;
    const height = containerRef.current.clientHeight;
    const newIndex = Math.round(scrollPos / height);
    if (newIndex !== activeIndex) {
      setActiveIndex(newIndex);
    }
  };

  const displayVideos = playlist.length > 0 ? playlist : MOCK_IMMERSION_VIDEOS;

  return (
    <div className="h-screen w-full relative overflow-hidden bg-rose-50/50">
      <div 
        ref={containerRef}
        onScroll={handleScroll}
        className="h-screen overflow-y-scroll snap-y snap-mandatory scroll-smooth scrollbar-hide"
      >
        {displayVideos.length > 0 ? (
          displayVideos.map((video, idx) => (
            <ImmersionStage 
              key={(video as any).videoId || (video as any).id} 
              video={video as any} 
              isActive={activeIndex === idx} 
              index={idx}
              total={displayVideos.length}
            />
          ))
        ) : (
          <div className="h-full flex flex-col items-center justify-center p-10 text-center space-y-6">
             <div className="w-24 h-24 rounded-full bg-white shadow-xl flex items-center justify-center text-rose-200">
                <Upload className="w-10 h-10" />
             </div>
             <div>
                <h2 className="text-3xl font-coquette-header text-gray-800">Your Stage is Empty</h2>
                <p className="font-coquette-body italic text-gray-400 mt-2">Upload a video to begin the AI analysis.</p>
             </div>
          </div>
        )}
      </div>
    </div>
  );
};

