const ImmersionStage: React.FC<ImmersionStageProps> = ({ video, isActive, index, total }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const [isUploadOpen, setIsUploadOpen] = useState(false);
  const [isMuted, setIsMuted] = useState(true);
  const [isPaused, setIsPaused] = useState(false);
  const [isTranslationVisible, setIsTranslationVisible] = useState(false);
  const [activeNodeId, setActiveNodeId] = useState<string | null>(null);

  const [isExplaining, setIsExplaining] = useState(false);
  const [explanation, setExplanation] = useState<ExplanationCard | null>(null);

  const { videoSources, layoutMode, clearPlaylist } = useImmersionStore();

  if (!video) return null;

  const videoSrc = videoSources[video.videoId || video.id] || video.videoUrl;
  const dialogueData = video.nodes || video.dialogue || [];

  const handleTimeUpdate = () => {
    if (!videoRef.current) return;
    const time = videoRef.current.currentTime;
    const syncTime = time + 0.2; 

    const currentLine = dialogueData.find((node: any) => 
      syncTime >= node.timestampStart && syncTime <= node.timestampEnd
    );

    if (currentLine && currentLine.id !== activeNodeId) {
      setActiveNodeId(currentLine.id);
      setIsTranslationVisible(false);
    }
  };

  const handleSeek = (timestamp: number) => {
    if (!videoRef.current) return;
    const player = videoRef.current;
    player.pause();
    player.currentTime = timestamp;

    const onSeeked = () => {
        player.play().catch(() => {});
        setIsPaused(false);
        player.removeEventListener('seeked', onSeeked);
    };

    player.addEventListener('seeked', onSeeked);
  };

  const handleExplainContext = async () => {
    const activeNode = dialogueData.find((node: any) => node.id === activeNodeId);
    if (!activeNode) return;

    const fullSentence = activeNode.japanese.map((t: any) => t.text).join('');
    setIsExplaining(true);
    try {
      const data = await explainToken(fullSentence, fullSentence);
      setExplanation(data);
    } catch (e) {
      console.error(e);
    } finally {
      setIsExplaining(false);
    }
  };

  const handleRefresh = () => {
    if (confirm("Reset current session? This will clear all transcripts and return to the start screen.")) {
      clearPlaylist();
    }
  };

  useEffect(() => {
    if (videoRef.current) {
      if (isActive) {
        videoRef.current.play().catch(() => {});
        setIsPaused(false);
      } else {
        videoRef.current.pause();
        setIsPaused(true);
      }
    }
  }, [isActive]);

  const togglePlay = () => {
    if (!videoRef.current) return;
    if (videoRef.current.paused) {
      videoRef.current.play();
      setIsPaused(false);
    } else {
      videoRef.current.pause();
      setIsPaused(true);
    }
  };

  const isYouTubeMode = layoutMode === 'stacked';

  return (
    <div className="h-screen w-full snap-start flex flex-col bg-[#fffcfc]">
      <header className="h-[60px] w-full border-b border-rose-100 bg-white px-8 flex items-center justify-between shrink-0 z-[60]">
         <div className="flex items-center gap-3">
            <div className="p-1.5 rounded-lg bg-rose-50 text-coquette-accent">
               <Clapperboard className="w-4 h-4" />
            </div>
            <div className="flex flex-col">
               <h1 className="text-base font-coquette-header text-coquette-text leading-none tracking-tight">Immersion Theater</h1>
               <span className="text-[8px] font-black text-rose-300 uppercase tracking-[0.2em] mt-0.5">
                  {isYouTubeMode ? 'YouTube Mode' : 'TikTok Mode'}
               </span>
            </div>
         </div>

         <div className="flex items-center gap-3">
            <button 
              onClick={handleRefresh}
              className="flex items-center gap-2 px-3 py-1.5 rounded-full bg-white border border-rose-100 text-coquette-subtext hover:text-rose-400 hover:bg-rose-50 transition-all shadow-sm group"
              title="Reset Session"
            >
               <RotateCcw className="w-3.5 h-3.5 group-hover:rotate-[-45deg] transition-transform" />
               <span className="text-[10px] font-bold uppercase tracking-widest hidden sm:inline">Reset</span>
            </button>
            <button onClick={() => setIsUploadOpen(true)} className="flex items-center gap-2 px-4 py-1.5 rounded-full bg-white border border-rose-100 text-rose-400 hover:bg-rose-50 transition-all shadow-sm group">
               <Plus className="w-3.5 h-3.5 group-hover:rotate-90 transition-transform" />
               <span className="text-[10px] font-bold uppercase tracking-widest">Ingest Media</span>
            </button>
            <div className="h-8 w-px bg-rose-50" />
            <div className="flex flex-col items-end min-w-[60px]">
               <span className="text-[8px] font-black text-coquette-subtext uppercase tracking-widest">Scene</span>
               <span className="text-[10px] font-bold text-coquette-text">{index + 1} of {total}</span>
            </div>
         </div>
      </header>

      <div className={`flex-1 flex overflow-hidden ${isYouTubeMode ? 'flex-col' : 'flex-row'}`}>
        <div className={`
          flex flex-col transition-all duration-500 overflow-y-auto custom-scrollbar bg-black/5
          ${isYouTubeMode ? 'w-full h-[65%] items-center p-6' : 'w-auto max-w-[50%] h-full items-center justify-center p-8'}
        `}>
          <div className={`
            relative rounded-[32px] overflow-hidden shadow-2xl border border-rose-100 bg-black group
            ${isYouTubeMode ? 'w-full max-w-5xl aspect-video' : 'h-full max-h-[80vh] aspect-[9/16]'}
          `}>
            <video
              ref={videoRef}
              src={videoSrc}
              onTimeUpdate={handleTimeUpdate}
              loop
              muted={isMuted}
              playsInline
              onClick={togglePlay}
              className="w-full h-full object-contain cursor-pointer"
            />

            <AnimatePresence>
              {isPaused && (
                <motion.div 
                  initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
                  className="absolute inset-0 flex items-center justify-center bg-black/30 pointer-events-none"
                >
                  <PlayIcon className="w-16 h-16 text-white/90 drop-shadow-lg" />
                </motion.div>
              )}
            </AnimatePresence>
          </div>

          <div className={`
            mt-6 w-full flex items-center justify-between px-6 py-3 rounded-[40px] bg-white border border-rose-100 shadow-[0_15px_40px_rgba(244,172,183,0.15)] relative
            ${isYouTubeMode ? 'max-w-xl' : 'max-w-xs'}
          `}>
             <button 
                onClick={() => { setIsMuted(!isMuted); if(videoRef.current) videoRef.current.muted = !isMuted; }}
                className={`
                  relative w-11 h-11 rounded-full flex items-center justify-center transition-all duration-300 overflow-hidden
                  ${isMuted ? 'bg-gray-100 text-gray-300' : 'bg-rose-50 text-rose-400 shadow-inner'}
                `}
                title={isMuted ? "Unmute" : "Mute"}
             >
                <AnimatePresence mode="wait">
                  <motion.div
                    key={isMuted ? 'muted' : 'unmuted'}
                    initial={{ scale: 0.5, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} exit={{ scale: 0.5, opacity: 0 }}
                  >
                    {isMuted ? <VolumeX className="w-5 h-5" /> : <Music className="w-5 h-5" />}
                  </motion.div>
                </AnimatePresence>
                {!isMuted && (
                  <motion.div 
                    animate={{ scale: [1, 1.4], opacity: [0.3, 0] }}
                    transition={{ repeat: Infinity, duration: 2 }}
                    className="absolute inset-0 bg-rose-200 rounded-full"
                  />
                )}
             </button>

             <button 
                onClick={handleExplainContext}
                disabled={!activeNodeId || isExplaining}
                className={`
                  flex items-center gap-2.5 px-6 py-2.5 rounded-full font-bold transition-all shadow-md active:scale-95
                  ${!activeNodeId ? 'bg-gray-100 text-gray-300' : 'bg-coquette-accent text-white hover:bg-[#ff9eb0] shadow-rose-100'}
                `}
             >
                {isExplaining ? <Loader2 className="w-3.5 h-3.5 animate-spin" /> : <Sparkles className="w-3.5 h-3.5" />}
                <span className="uppercase font-black text-[9px] tracking-widest whitespace-nowrap">Sensei Insight</span>
             </button>

             <button 
                onClick={() => setIsTranslationVisible(!isTranslationVisible)}
                disabled={!activeNodeId}
                className={`p-2.5 rounded-full transition-all ${isTranslationVisible ? 'bg-rose-500 text-white shadow-sm' : 'bg-rose-50 text-rose-400'} disabled:opacity-30`}
             >
                {isTranslationVisible ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
             </button>
          </div>
        </div>

        <div className={`
          flex-1 h-full bg-[#fffcfc]/40 backdrop-blur-sm shadow-inner transition-all duration-500
          ${isYouTubeMode ? 'border-t' : 'border-l'} border-rose-100
        `}>
           <TranscriptStream 
              nodes={dialogueData} 
              activeNodeId={activeNodeId}
              onSeek={handleSeek}
              isTranslationVisible={isTranslationVisible}
           />
        </div>
      </div>

      <UploadGateway isOpen={isUploadOpen} onClose={() => setIsUploadOpen(false)} />
      <SenseiModal explanation={explanation} isLoading={isExplaining} onClose={() => setExplanation(null)} />
    </div>
  );
};

export default ImmersionStage;

import React, { useEffect, useRef, useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { DialogueLine } from '../../types';
import { ImmersionToken, TokenType } from '../../types/immersionSchema';
import { ScrollText, Navigation2 } from 'lucide-react';

interface TranscriptStreamProps {
  nodes?: (DialogueLine | any)[];
  activeNodeId: string | null;
  onSeek: (timestamp: number) => void;
  isTranslationVisible: boolean;
}

const TokenChip: React.FC<{ 
  token: ImmersionToken; 
  isEnglish?: boolean;
  isActive: boolean;
  onTokenClick: (groupId: number) => void;
}> = ({ token, isEnglish = false, isActive, onTokenClick }) => {
  const isPunctuation = token.type === TokenType.PUNCTUATION;
  const isGrammar = token.type === TokenType.GRAMMAR;

  // Concept mapping logic: Only highlight if groupId is valid (non-zero)
  const canHighlight = token.groupId !== 0;

  return (
    <motion.span 
      onClick={(e) => {
        e.stopPropagation();
        if (canHighlight) onTokenClick(token.groupId);
      }}
      className={`
        inline-flex px-0.5 py-0.5 rounded-md transition-all duration-200 cursor-pointer
        ${isActive ? 'bg-emerald-50 text-emerald-600 ring-1 ring-emerald-200 shadow-sm z-10 scale-105' : ''}
        ${!isActive && isPunctuation ? 'text-gray-300' : ''}
        ${!canHighlight ? 'cursor-default' : 'hover:bg-rose-50/50'}
      `}
    >
      <span className={`
        font-coquette-rounded leading-tight select-none
        ${isEnglish ? 'text-[10px] md:text-[11px]' : 'text-sm md:text-base'}
        ${!isActive && isGrammar ? 'text-rose-400 font-medium' : ''}
        ${!isActive && !isGrammar && !isPunctuation ? (isEnglish ? 'text-gray-500 font-medium' : 'font-bold text-coquette-text') : ''}
        ${isActive ? 'font-bold underline decoration-emerald-200 decoration-2 underline-offset-2' : ''}
      `}>
        {token.text}
      </span>
    </motion.span>
  );
};

const TranscriptLine: React.FC<{ 
  line: DialogueLine;
  isActive: boolean;
  isTranslationVisible: boolean;
  onSeek: (timestamp: number) => void;
  activeGroupId: number | null;
  onTokenClick: (groupId: number) => void;
}> = ({ line, isActive, isTranslationVisible, onSeek, activeGroupId, onTokenClick }) => {
  const lineRef = useRef<HTMLDivElement>(null);

  // Auto-scroll to active line
  useEffect(() => {
    if (isActive && lineRef.current) {
      lineRef.current.scrollIntoView({ behavior: 'smooth', block: 'center' });
    }
  }, [isActive]);

  // Logic: Show translation if eye-button is ON OR a word is specifically selected for detail
  const shouldRevealTranslation = isTranslationVisible || (activeGroupId !== null);

  const handleTokenInteraction = (groupId: number) => {
    // If clicking a word on a line that isn't the current one, seek the video
    if (!isActive) {
        onSeek(line.timestampStart);
    }
    onTokenClick(groupId);
  };

  return (
    <div 
      ref={lineRef}
      className={`mb-3 flex gap-2.5 transition-all duration-500 ${isActive ? 'scale-[1.01]' : 'opacity-70'}`}
    >
      {/* Navigation (The Sidebar / Gutter) */}
      <div className="flex flex-col items-center pt-1.5">
        <button
          onClick={() => onSeek(line.timestampStart)}
          title="Jump video to this line"
          className={`
            w-1 flex-1 rounded-full transition-all duration-300 group relative
            ${isActive ? 'bg-rose-400 shadow-[0_0_8px_rgba(244,172,183,0.6)]' : 'bg-rose-100/80 hover:bg-rose-300'}
          `}
        >
          <div className="absolute left-1/2 -translate-x-1/2 -top-1 opacity-0 group-hover:opacity-100 transition-opacity">
             <Navigation2 className="w-2 h-2 text-rose-400 fill-current" />
          </div>
        </button>
      </div>

      {/* Dialogue Content */}
      <motion.div
        animate={{ 
          backgroundColor: isActive ? 'rgba(255, 255, 255, 0.95)' : 'rgba(255, 255, 255, 0.3)',
          borderColor: isActive ? '#fde2e4' : 'transparent',
          boxShadow: isActive ? '0 10px 25px -5px rgba(244, 172, 183, 0.12)' : 'none'
        }}
        className="flex-1 text-left py-2.5 px-4 rounded-[20px] border-2 transition-shadow"
      >
        <div className="flex flex-col gap-1.5">
          {/* Japanese Token Stream */}
          <div className="flex flex-wrap items-end gap-x-0.5">
            {line.japanese.map((t, i) => (
              <TokenChip 
                key={i} 
                token={t} 
                isActive={activeGroupId === t.groupId && t.groupId !== 0}
                onTokenClick={handleTokenInteraction}
              />
            ))}
          </div>

          {/* English Stream - The Drawer */}
          <AnimatePresence>
            {isActive && shouldRevealTranslation && (
              <motion.div
                initial={{ height: 0, opacity: 0 }}
                animate={{ height: 'auto', opacity: 1 }}
                exit={{ height: 0, opacity: 0 }}
                transition={{ duration: 0.3, ease: "circOut" }}
                className="overflow-hidden"
              >
                <div className="flex flex-wrap items-center gap-x-0.5 border-l border-emerald-100 pl-3 mt-1.5 mb-1 py-0.5">
                  {line.english.map((t, i) => (
                    <TokenChip 
                      key={i} 
                      token={t} 
                      isEnglish 
                      isActive={activeGroupId === t.groupId && t.groupId !== 0}
                      onTokenClick={handleTokenInteraction}
                    />
                  ))}
                </div>
              </motion.div>
            )}
          </AnimatePresence>
        </div>
      </motion.div>
    </div>
  );
};

const TranscriptSkeleton = () => (
  <div className="space-y-6 animate-pulse mt-4">
    {[1, 2, 3, 4].map(i => (
      <div key={i} className="flex gap-3 px-6">
        <div className="w-1 h-10 bg-rose-50 rounded-full" />
        <div className="flex-1 space-y-2">
          <div className="h-5 w-40 bg-rose-100/20 rounded-lg" />
          <div className="h-3 w-28 bg-gray-100/50 rounded-lg" />
        </div>
      </div>
    ))}
  </div>
);

const TranscriptStream: React.FC<TranscriptStreamProps> = ({ nodes, activeNodeId, onSeek, isTranslationVisible }) => {
  const [activeGroupId, setActiveGroupId] = useState<number | null>(null);
  const hasContent = nodes && nodes.length > 0;

  // Clear highlight when switching nodes naturally through video playback
  // but keep it if seeking manually via TokenChip click
  useEffect(() => {
    // If activeGroupId is set, it likely came from a click, 
    // so we don't want to immediately wipe it when the activeNodeId changes 
    // due to the resulting seek.
    // However, if playing naturally, we want to clear.
  }, [activeNodeId]);

  const handleTokenClick = (groupId: number) => {
    setActiveGroupId(prev => prev === groupId ? null : groupId);
  };

  return (
    <div className="h-full flex flex-col overflow-hidden relative">
      <div className="flex-1 overflow-y-auto p-4 lg:p-6 scrollbar-thin scrollbar-thumb-rose-100 bg-[url('https://www.transparenttextures.com/patterns/cream-paper.png')]">
        <div className="max-w-2xl mx-auto py-6">
          {!hasContent ? (
             <div className="flex flex-col items-center justify-center py-20 text-center">
                <div className="p-4 rounded-full bg-white shadow-sm border border-rose-50 text-rose-200 mb-4">
                  <ScrollText className="w-8 h-8" />
                </div>
                <h3 className="font-coquette-header text-lg text-gray-700 font-bold mb-1">Analyzing Dialogue...</h3>
                <TranscriptSkeleton />
             </div>
          ) : (
            nodes.map((line) => (
              <TranscriptLine 
                key={line.id} 
                line={line} 
                isActive={activeNodeId === line.id}
                isTranslationVisible={isTranslationVisible}
                onSeek={onSeek}
                activeGroupId={activeGroupId}
                onTokenClick={handleTokenClick}
              />
            ))
          )}
          <div className="h-32" />
        </div>
      </div>
    </div>
  );
};

export default TranscriptStream;
